<?php

namespace App\Console\Commands;

use App\Models\News;
use Illuminate\Console\Command;
use Carbon\Carbon;

class SeedRecentNews extends Command
{
    protected $signature   = 'news:seed';
    protected $description = '한인 커뮤니티 뉴스 샘플 데이터 100건 이상 생성';

    public function handle(): int
    {
        $sources = ['미주한국일보', '미주중앙일보', '코리아타임스', '코리아헤럴드'];

        $articles = $this->getArticles();

        $this->info('뉴스 시드 데이터 생성 중...');

        $count = 0;
        foreach ($articles as $i => $article) {
            $daysAgo     = rand(0, 180);
            $publishedAt = Carbon::now()->subDays($daysAgo)->subHours(rand(0, 23))->subMinutes(rand(0, 59));
            $source      = $sources[array_rand($sources)];

            News::updateOrCreate(
                ['url' => "https://news.somekorean.com/articles/" . ($i + 1)],
                [
                    'title'        => $article['title'],
                    'summary'      => $article['summary'],
                    'content'      => $article['content'],
                    'source'       => $source,
                    'category'     => $article['category'],
                    'image_url'    => null,
                    'published_at' => $publishedAt,
                ]
            );
            $count++;
        }

        $this->info("뉴스 시드 완료: {$count}건 생성");

        return self::SUCCESS;
    }

    private function getArticles(): array
    {
        return [
            // ── 정치/사회 (이민, 비자, 정책) ──
            ['title' => '미국 이민국, H-1B 비자 추첨 결과 발표...한인 지원자 관심 집중', 'summary' => '미국 이민국(USCIS)이 2026 회계연도 H-1B 비자 추첨 결과를 발표했다. 한인 IT 전문가들 사이에서 큰 관심을 모으고 있으며, 올해 지원자 수는 역대 최다를 기록했다.', 'category' => '정치/사회', 'content' => "미국 내 한인 커뮤니티에서 H-1B 비자 추첨 결과에 대한 관심이 높아지고 있다. 올해 약 78만 건의 등록 중 85,000명이 선정되었으며, 이는 역대 최고 경쟁률을 기록한 것이다.\n\n특히 한인 지원자의 수가 전년 대비 15% 증가한 것으로 나타났다. 이민 전문 변호사들은 '한국의 IT 기업과 스타트업에서 미국 진출을 위해 H-1B를 활용하는 사례가 늘고 있다'고 분석했다.\n\n선정되지 못한 지원자들을 위해 USCIS는 대안적 비자 옵션에 대한 가이드라인을 발표할 예정이다. O-1 비자나 L-1 비자 등 대안을 검토하는 것도 좋은 방법이라는 조언이다.\n\n한인 이민변호사협회는 올해 추첨 결과에 대한 무료 상담 세션을 마련하여 지원자들의 궁금증을 해소할 계획이라고 밝혔다."],
            ['title' => '영주권 문호 업데이트, 취업이민 3순위 전진', 'summary' => '국무부가 발표한 최신 비자 문호에서 취업이민 3순위가 2개월 전진했다. 한인 커뮤니티에서는 대기 시간 단축에 대한 기대감이 높아지고 있다.', 'category' => '정치/사회', 'content' => "국무부가 발표한 최신 비자 문호(Visa Bulletin)에서 취업이민 3순위(EB-3)의 우선일자가 2개월 전진하며 한인 커뮤니티에 희소식을 전했다.\n\n이번 변경으로 인도 출생자를 제외한 대부분의 국가 출생자들의 대기 기간이 크게 단축될 전망이다. 한국 출생자의 경우 약 1년 이내에 영주권을 받을 수 있을 것으로 예상된다.\n\n이민 전문가들은 바이든 행정부의 이민 정책 기조 변화가 이번 문호 전진에 영향을 미쳤을 가능성이 있다고 분석했다. 특히 STEM 분야 인력 확보를 위한 정책적 노력이 반영된 것으로 보인다.\n\n한인 이민자들 사이에서는 NIW(국익면제) 청원과 EB-3 다운그레이드 전략에 대한 관심도 높아지고 있다."],
            ['title' => '뉴욕시 한인회, 아시안 혐오범죄 대응 타운홀 미팅 개최', 'summary' => '뉴욕시 한인회가 최근 증가하는 아시안 혐오범죄에 대응하기 위한 타운홀 미팅을 개최한다. 지역 경찰서장과 시의원이 참석하여 안전 대책을 논의할 예정이다.', 'category' => '정치/사회', 'content' => "뉴욕시 한인회가 아시안 혐오범죄 증가에 따른 커뮤니티 안전 대책을 논의하기 위한 타운홀 미팅을 오는 토요일 개최한다고 발표했다.\n\n이번 미팅에는 지역 경찰서장, 시의원, 그리고 아시안 인권 단체 대표들이 참석하여 최근 발생한 혐오범죄 현황을 공유하고 대응 방안을 논의할 예정이다.\n\n한인회 관계자는 지난 6개월간 뉴욕 지역에서 보고된 아시안 대상 혐오범죄가 전년 동기 대비 30% 증가했다며, 커뮤니티 차원의 조직적 대응이 필요하다고 강조했다.\n\n또한 개인 안전 교육 프로그램과 무료 호신술 클래스도 함께 안내될 예정이다. 타운홀 미팅은 한국어와 영어 통역이 제공된다."],
            ['title' => 'LA 한인타운 투표소 확대, 유권자 등록 캠페인 시작', 'summary' => 'LA 카운티 선거관리위원회가 한인타운 지역에 투표소를 추가 설치한다고 발표했다. 한인 유권자 등록을 독려하기 위한 캠페인도 동시에 진행된다.', 'category' => '정치/사회', 'content' => "LA 카운티 선거관리위원회가 한인타운 지역에 3개의 투표소를 추가 설치하겠다고 발표했다. 이는 한인 유권자의 투표 접근성을 높이기 위한 조치이다.\n\n새 투표소는 한인타운 중심부인 올림픽 블러바드와 웨스턴 애비뉴 인근에 위치하며, 한국어 지원 직원이 상주할 예정이다.\n\n한인회와 시민단체들은 이에 발맞춰 한인 유권자 등록 캠페인을 본격 시작했다. 한인 마트, 교회, 커뮤니티 센터에서 등록 부스를 운영하며 투표 참여를 독려하고 있다.\n\n전문가들은 한인 유권자의 투표율이 다른 아시안 그룹에 비해 낮은 편이라며, 지역 정치에서 한인의 목소리를 높이기 위해 적극적인 참여가 필요하다고 강조했다."],
            ['title' => '연방법원, DACA 프로그램 일부 유지 판결...한인 드리머 안도', 'summary' => '연방 항소법원이 DACA 프로그램의 기존 수혜자에 대한 보호를 유지하는 판결을 내렸다. 한인 드리머들 사이에서 안도의 반응이 나오고 있다.', 'category' => '정치/사회', 'content' => "연방 제5순회 항소법원이 DACA(불법체류 청소년 추방유예) 프로그램의 기존 수혜자들에 대한 보호를 계속 유지하는 판결을 내렸다.\n\n이번 판결로 약 58만 명의 기존 DACA 수혜자들은 당분간 추방 걱정 없이 미국에서 생활하고 일할 수 있게 되었다. 다만 신규 신청은 여전히 받지 않는 상태이다.\n\n한인 드리머 단체 관계자는 이번 판결에 안도의 반응을 보이면서도, 근본적인 이민 개혁 없이는 불안정한 상황이 계속될 것이라며 의회의 입법 조치를 촉구했다.\n\n현재 미국에 거주하는 한인 DACA 수혜자는 약 7,000명으로 추정되며, 대부분 어린 시절 부모를 따라 미국에 입국한 1.5세대이다."],
            ['title' => '시민권 시험 개정안 발표, 한국어 번역 가이드 제공', 'summary' => 'USCIS가 시민권 시험 개정안을 발표하면서 한국어를 포함한 다국어 학습 가이드를 제공한다. 고령 한인 영주권자들의 시민권 취득에 도움이 될 전망이다.', 'category' => '정치/사회', 'content' => "USCIS가 시민권 시험(Naturalization Test) 개정안을 공식 발표하면서 한국어를 포함한 14개 언어의 학습 가이드를 함께 제공한다고 밝혔다.\n\n개정된 시험은 기존 100문제에서 128문제로 확대되며, 미국 역사와 정부 구조에 관한 문항이 강화되었다. 다만 65세 이상 영주권자에 대한 간소화 시험은 유지된다.\n\n한인 커뮤니티 센터에서는 시민권 시험 대비 무료 강좌를 확대 운영할 계획이다. 특히 영어에 어려움을 겪는 고령 한인들을 위한 맞춤형 프로그램이 마련된다.\n\n이민 전문가들은 시민권 취득이 투표권 행사와 가족 초청 이민 등에서 유리하다며, 자격이 되는 영주권자들의 적극적인 신청을 권유했다."],
            ['title' => '한인 2세 변호사, 최초 연방판사 후보 지명', 'summary' => '한인 2세 변호사가 연방지방법원 판사 후보로 지명되었다. 한인 커뮤니티에서는 역사적인 순간이라며 축하 분위기가 이어지고 있다.', 'category' => '정치/사회', 'content' => "한인 2세 변호사가 연방지방법원 판사 후보로 대통령의 지명을 받았다. 상원 인준이 완료되면 한인계 미국인 최초의 연방판사가 탄생하게 된다.\n\n지명된 변호사는 하버드 로스쿨 출신으로 20년간 연방검사와 대형 로펌에서 활동해왔으며, 시민권 및 이민법 분야에서 전문성을 인정받아왔다.\n\n한인 변호사협회장은 이번 지명이 한인 커뮤니티의 위상을 높이는 역사적인 순간이라며, 상원 인준 과정에서 적극적으로 지지 활동을 펼치겠다고 밝혔다.\n\n한인 법조계에서는 이번 지명을 계기로 더 많은 한인 법률가들이 공직에 진출하는 계기가 될 것이라는 기대의 목소리가 높다."],
            ['title' => '이민 개혁 법안 상원 통과 전망, 한인 사회 촉각', 'summary' => '초당적 이민 개혁 법안이 상원 표결을 앞두고 있다. 가족 초청 이민과 취업 이민 카테고리에 변화가 예상되어 한인 사회가 주목하고 있다.', 'category' => '정치/사회', 'content' => "초당적 이민 개혁 법안이 상원 본회의 표결을 앞두고 있어 한인 사회가 촉각을 곤두세우고 있다.\n\n법안의 핵심 내용은 가족 초청 이민 비자 쿼터를 연간 22만 6천 건에서 30만 건으로 확대하고, 취업 이민 비자도 14만 건에서 20만 건으로 늘리는 것이다.\n\n또한 STEM 분야 석박사 학위 소지자에 대한 영주권 우선 처리 조항이 포함되어, 미국 대학을 졸업한 한인 유학생들에게 유리한 환경이 조성될 수 있다.\n\n한인 이민단체들은 법안 통과를 위한 로비 활동을 강화하고 있으며, 의원실 방문과 서명 운동 등을 통해 한인 사회의 목소리를 전달하고 있다."],
            ['title' => '경찰, 한인타운 노인 대상 보이스피싱 주의보 발령', 'summary' => '한인타운 경찰이 한국어로 전화를 걸어 검찰을 사칭하는 보이스피싱에 대한 주의보를 발령했다. 최근 한 달간 피해 사례가 급증하고 있다.', 'category' => '정치/사회', 'content' => "LAPD 올림픽 파출소가 한인타운 지역 노인들을 대상으로 한 보이스피싱 범죄에 대한 주의보를 발령했다.\n\n범인들은 한국어로 전화를 걸어 검찰이나 금융감독원을 사칭하며, 개인정보 유출 또는 범죄 연루를 빌미로 송금을 요구하는 수법을 사용하고 있다.\n\n지난 한 달간 한인타운에서만 12건의 피해 사례가 접수되었으며, 피해 총액은 약 45만 달러에 달한다. 피해자 대부분이 60세 이상 고령 한인이었다.\n\n경찰은 정부기관은 절대 전화로 송금을 요구하지 않는다며, 의심스러운 전화를 받으면 즉시 끊고 경찰이나 한인회에 신고해달라고 당부했다."],
            ['title' => '한인회, 센서스 참여 독려 캠페인 본격 시작', 'summary' => '전미한인회가 2026년 중간 센서스 조사 참여를 독려하는 캠페인을 시작했다. 정확한 인구 집계가 한인 커뮤니티 예산 배정에 직접적인 영향을 미친다고 강조했다.', 'category' => '정치/사회', 'content' => "전미한인회총연합회가 2026년 미국 커뮤니티 서베이(ACS) 참여를 독려하는 대대적인 캠페인을 시작했다.\n\n정확한 인구 집계는 연방 예산 배정, 선거구 획정, 공공 서비스 배분에 직접적인 영향을 미치기 때문에 한인 커뮤니티의 적극적인 참여가 중요하다.\n\n특히 2020년 센서스에서 한인의 응답률이 상대적으로 낮았던 점을 감안하여, 이번에는 한국어 안내 자료와 전화 통역 서비스를 대폭 확대했다.\n\n한인회 관계자는 센서스 정보는 철저히 보호되며 이민 단속에 사용되지 않는다며, 불법체류 신분과 관계없이 모든 한인이 응답해달라고 호소했다."],
            ['title' => '뉴저지 한인 밀집 지역, 새 하원의원 선거 관심', 'summary' => '뉴저지 버겐카운티 지역의 하원의원 보궐선거에서 한인 유권자의 표심이 주목받고 있다. 두 후보 모두 한인타운을 방문하여 지지를 호소하고 있다.', 'category' => '정치/사회', 'content' => "뉴저지 버겐카운티의 하원의원 보궐선거를 앞두고 한인 유권자들의 표심에 관심이 집중되고 있다.\n\n이 지역은 미국 내 한인 인구가 가장 밀집된 곳 중 하나로, 등록 한인 유권자 수가 약 3만 5천 명에 달한다. 접전이 예상되는 이번 선거에서 한인 표가 승패를 가를 수 있다는 분석이다.\n\n양당 후보 모두 팰리세이즈 파크와 포트리 등 한인 밀집 지역을 적극 방문하며 한인 유권자의 지지를 호소하고 있다. 한국어 선거 광고도 늘어나고 있다.\n\n한인 정치 전문가들은 이번 선거를 통해 한인 커뮤니티의 정치적 영향력을 확인할 수 있는 좋은 기회라며 투표 참여를 독려하고 있다."],
            ['title' => '미 대사관, 한국인 관광비자 인터뷰 대기 기간 단축', 'summary' => '주한미국대사관이 비이민 비자 인터뷰 대기 기간을 대폭 단축했다고 발표했다. 한국인 관광객 및 사업 방문자들에게 긍정적인 변화가 예상된다.', 'category' => '정치/사회', 'content' => "주한미국대사관이 B1/B2 비이민 비자 인터뷰 대기 기간을 기존 90일에서 30일 이내로 대폭 단축했다고 공식 발표했다.\n\n이는 코로나19 팬데믹 이후 누적된 비자 처리 지연을 해소하기 위한 조치의 일환이다. 추가 영사관 직원 배치와 인터뷰 시간 연장이 단축의 배경이다.\n\n한국 여행업계와 기업들은 이번 조치를 환영하며, 미국 관광 및 출장 수요가 더욱 증가할 것으로 전망했다.\n\n다만 비자 갱신의 경우 인터뷰 면제 프로그램(드롭박스)의 대기 기간은 여전히 60일 이상이므로, 출국 일정에 여유를 두고 신청할 것을 권장하고 있다."],

            // ── 경제 (부동산, 세금, 비즈니스) ──
            ['title' => 'LA 한인타운 부동산 시장, 상업용 건물 거래 활발', 'summary' => 'LA 한인타운 상업용 부동산 거래가 올해 들어 크게 증가했다. 특히 식당과 소매점 임대 수요가 높아지면서 임대료도 상승세를 보이고 있다.', 'category' => '경제', 'content' => "LA 한인타운의 상업용 부동산 시장이 활기를 띠고 있다. 올해 1분기 거래량이 전년 동기 대비 25% 증가했으며, 특히 식당과 소매점 공간에 대한 수요가 높다.\n\n한인 부동산 전문가에 따르면, 한인타운 핵심 상권인 올림픽 블러바드와 6번가 인근의 상업용 건물 임대료가 평방피트당 3.5달러에서 4.2달러로 상승했다.\n\n이러한 상승세는 K-푸드 열풍에 힘입어 한식당 창업이 늘어난 것과, 팬데믹 이후 오프라인 매장 수요가 회복된 것이 주요 원인으로 분석된다.\n\n다만 일부 전문가들은 임대료 상승이 영세 소상공인들에게 부담이 될 수 있다며 주의를 당부했다."],
            ['title' => '달러-원 환율 1,300원대 돌파, 한인 송금 영향', 'summary' => '달러-원 환율이 1,300원대를 돌파하면서 한국으로 송금하는 한인들의 부담이 줄었다. 전문가들은 당분간 강달러 기조가 이어질 것으로 전망했다.', 'category' => '경제', 'content' => "달러-원 환율이 1,300원대를 돌파하면서 미주 한인들의 한국 송금에 유리한 환경이 조성되고 있다.\n\n한인 송금업체에 따르면 최근 한 달간 한국으로의 송금 건수가 전월 대비 18% 증가했다. 부모님 용돈, 부동산 투자, 자녀 학비 송금 등이 주요 목적이다.\n\n환율 전문가는 미 연준의 금리 정책과 한국 경제 상황을 고려할 때 당분간 강달러 기조가 이어질 것으로 전망했다. 다만 급격한 환율 변동에 대비해 분할 송금을 권장했다.\n\n한편 한인 은행들은 환전 우대 이벤트를 실시하며 고객 유치에 나서고 있다."],
            ['title' => '한인 소상공인 대출 프로그램, 연방 지원금 확대', 'summary' => 'SBA가 소수민족 소상공인을 위한 대출 프로그램을 확대한다고 발표했다. 한인 비즈니스 오너들도 저금리 대출 혜택을 받을 수 있게 되었다.', 'category' => '경제', 'content' => "미국 중소기업청(SBA)이 소수민족 소상공인을 위한 대출 프로그램 예산을 50억 달러에서 75억 달러로 확대한다고 발표했다.\n\n이번 확대로 한인 소상공인들도 연 5% 이하의 저금리로 최대 35만 달러까지 대출받을 수 있게 되었다. 특히 창업 5년 이내의 신규 사업자에게 우대 조건이 적용된다.\n\n한인 상공회의소는 신청 절차를 한국어로 안내하는 워크숍을 개최하고, 서류 작성 지원 서비스도 제공할 계획이다.\n\n이민 1세대 소상공인들 사이에서는 언어 장벽으로 인해 이러한 혜택을 놓치는 경우가 많았는데, 이번 한국어 지원 확대로 접근성이 크게 개선될 것으로 기대된다."],
            ['title' => '미주 한인 스타트업 투자 유치 급증, AI 분야 주목', 'summary' => '미주 지역 한인 스타트업들의 벤처 투자 유치가 전년 대비 40% 증가했다. 특히 AI와 헬스테크 분야에서 한인 창업자들의 활약이 눈에 띈다.', 'category' => '경제', 'content' => "미주 지역에서 한인이 창업한 스타트업들의 벤처 투자 유치가 급증하고 있다. 올해 상반기 기준으로 한인 창업 스타트업의 총 투자 유치액은 약 12억 달러로, 전년 대비 40% 증가했다.\n\n특히 AI(인공지능)와 헬스테크 분야에서 한인 창업자들의 활약이 돋보인다. 실리콘밸리에서 AI 기반 의료 진단 플랫폼을 개발한 한인 스타트업은 최근 시리즈B에서 8천만 달러를 유치했다.\n\n한인 창업자 네트워크 관계자는 한국의 우수한 공학 교육과 미국 시장에 대한 이해가 결합되어 글로벌 경쟁력을 갖춘 스타트업이 많이 탄생하고 있다고 분석했다.\n\n한인 벤처캐피탈 협회도 한인 스타트업 투자 펀드를 조성하여 초기 단계 한인 창업자들을 지원할 계획이다."],
            ['title' => '2026년 세금 보고 시즌 시작, 한인 납세자 유의사항', 'summary' => 'IRS가 2026년 세금 보고 시즌을 공식 시작했다. 한인 세무사들은 올해 변경된 세법 중 해외 금융계좌 신고 강화에 특히 주의해야 한다고 당부했다.', 'category' => '경제', 'content' => "IRS가 2026년 세금 보고 시즌을 공식 시작했다. 올해 세금 보고 마감일은 4월 15일이며, 연장 신청 시 10월 15일까지 가능하다.\n\n한인 세무사회는 올해 특히 주의해야 할 사항으로 해외 금융계좌 신고(FBAR) 기준 강화를 꼽았다. 한국에 1만 달러 이상의 금융자산을 보유한 경우 반드시 신고해야 하며, 미신고 시 최대 10만 달러의 벌금이 부과될 수 있다.\n\n또한 가상화폐 거래에 대한 과세 규정도 강화되었다. 가상화폐 매매 차익은 자본이득세 대상이며, 모든 거래 내역을 정확히 보고해야 한다.\n\n한인 세무사들은 무료 세금 상담 핫라인을 운영하고 있으며, 저소득 한인을 위한 무료 세금 보고 서비스도 제공하고 있다."],
            ['title' => '한인 마트 체인, 동부 지역 신규 매장 5곳 오픈 예정', 'summary' => 'H마트가 올해 동부 지역에 5개의 신규 매장을 오픈할 계획이라고 발표했다. 한인 식품 수요 증가와 함께 K-푸드의 인기가 반영된 결과다.', 'category' => '경제', 'content' => "H마트가 올해 미국 동부 지역에 5개의 신규 매장을 오픈할 계획이라고 발표했다. 새 매장은 뉴저지 2곳, 펜실베이니아 1곳, 버지니아 2곳에 들어설 예정이다.\n\n이번 확장은 K-푸드에 대한 미국 주류 사회의 관심 증가를 반영한 것이다. H마트 관계자는 한인뿐 아니라 비한인 고객의 비율이 40%를 넘어섰다고 밝혔다.\n\n신규 매장에는 한식 푸드코트와 베이커리가 함께 입점하여 쇼핑과 식사를 동시에 즐길 수 있는 복합 공간으로 꾸며진다.\n\n한인 식품 유통업계에서는 김치, 라면, 떡 등 한국 식품의 미국 내 매출이 매년 20% 이상 성장하고 있어 추가 확장이 이어질 것으로 전망하고 있다."],
            ['title' => '플러싱 한인 상가 임대료 급등, 소상공인 부담 가중', 'summary' => '뉴욕 플러싱 지역 한인 상가의 임대료가 전년 대비 20% 이상 급등했다. 일부 소상공인들은 폐업을 고려하고 있다고 전했다.', 'category' => '경제', 'content' => "뉴욕 플러싱 지역 한인 상가의 임대료가 전년 대비 20% 이상 급등하면서 소상공인들의 부담이 가중되고 있다.\n\n메인스트리트와 유니언 스트리트 일대의 월 임대료가 평균 6,000달러에서 7,500달러로 올랐으며, 핵심 상권의 경우 1만 달러를 넘는 곳도 있다.\n\n한인 네일살롱 운영자 김 모 씨는 임대료가 매출의 35%를 차지하게 되었다며 폐업을 심각하게 고려하고 있다고 전했다.\n\n한인 상인회는 임대료 안정화를 위한 상업용 임대료 규제 법안을 지지하며 시의회에 탄원서를 제출할 계획이다."],
            ['title' => '한국 주식 투자 열풍, 미주 한인 서학개미 증가', 'summary' => '미주 한인들 사이에서 한국 주식 직접 투자 열풍이 불고 있다. 삼성전자와 SK하이닉스 등 반도체 관련주가 인기를 끌고 있다.', 'category' => '경제', 'content' => "미주 한인들 사이에서 한국 주식에 직접 투자하는 이른바 서학개미가 급증하고 있다. 한국 증권사들의 해외 거주자 계좌 개설이 전년 대비 60% 증가했다.\n\n특히 삼성전자, SK하이닉스 등 반도체 관련주와 현대자동차, 기아 등 전기차 관련주가 한인 투자자들 사이에서 인기를 끌고 있다.\n\n한인 재정 전문가는 환율 우위를 활용한 한국 주식 투자가 포트폴리오 다변화에 도움이 될 수 있다고 조언했다. 다만 해외 투자에 따른 세금 보고 의무를 잊지 말아야 한다고 강조했다.\n\n한편 한인 투자 동호회에서는 정기적인 투자 세미나를 개최하여 한국 증시 동향과 투자 전략을 공유하고 있다."],
            ['title' => '한인타운 식당 인건비 상승, 메뉴 가격 인상 불가피', 'summary' => '캘리포니아 최저임금 인상으로 한인타운 식당들의 인건비 부담이 커졌다. 대부분의 한식당이 메뉴 가격을 10~15% 인상할 계획이다.', 'category' => '경제', 'content' => "캘리포니아 주의 최저임금이 시간당 16달러에서 20달러로 인상되면서 한인타운 식당들의 경영 부담이 크게 늘어났다.\n\n한인 식당 협회에 따르면, 인건비가 매출의 40% 이상을 차지하게 된 식당이 전체의 65%에 달한다. 이에 따라 대부분의 한식당이 메뉴 가격을 10~15% 인상할 계획이다.\n\n일부 식당들은 키오스크 도입과 주방 자동화 설비 투자를 통해 인건비를 절감하려는 시도를 하고 있다. 또한 점심 특선 메뉴를 폐지하거나 영업시간을 단축하는 곳도 늘어나고 있다.\n\n소비자들 사이에서는 가격 인상에 대한 이해와 함께, 서비스 품질 유지에 대한 기대도 높아지고 있다."],
            ['title' => '한인 부동산 에이전트, 올해 주택시장 전망 발표', 'summary' => '한인 부동산 협회가 올해 미국 주택시장 전망을 발표했다. 금리 인하 기대감으로 하반기 거래 회복이 예상되지만, 매물 부족은 여전히 과제로 남아 있다.', 'category' => '경제', 'content' => "한인 부동산 협회가 2026년 미국 주택시장 전망 보고서를 발표했다. 보고서에 따르면 연준의 금리 인하 기대감으로 하반기부터 거래가 회복될 것으로 전망된다.\n\n현재 30년 고정 모기지 금리는 6.5% 수준이며, 하반기에는 5%대까지 낮아질 가능성이 있다. 이 경우 주택 구매 수요가 크게 늘어날 것으로 보인다.\n\n다만 매물 부족은 여전히 과제로 남아 있다. 기존 주택 소유자들이 낮은 금리의 기존 모기지를 유지하려 하면서 매물이 시장에 나오지 않는 잠금 효과가 지속되고 있다.\n\n한인 부동산 에이전트들은 첫 주택 구매자를 위한 정부 보조 프로그램과 다운페이먼트 지원 제도를 적극 활용할 것을 권유하고 있다."],
            ['title' => '한인 은행, 중소기업 특별 금리 프로그램 출시', 'summary' => '한미은행이 한인 중소기업을 위한 특별 저금리 대출 프로그램을 출시했다. 최대 50만 달러까지 경쟁력 있는 금리로 대출이 가능하다.', 'category' => '경제', 'content' => "한미은행이 한인 중소기업을 위한 특별 저금리 대출 프로그램을 출시했다. 이 프로그램을 통해 최대 50만 달러까지 프라임 레이트 대비 1% 낮은 금리로 대출받을 수 있다.\n\n대출 대상은 영업 2년 이상의 한인 소유 중소기업이며, 운전자금, 설비투자, 매장 확장 등 다양한 용도로 사용할 수 있다.\n\n한미은행 관계자는 한인 소상공인들이 대형 은행에서 대출 받기 어려운 점을 감안하여 심사 기준을 유연하게 적용하고 있다고 설명했다.\n\n이 프로그램은 올해 말까지 한시적으로 운영되며, 신청은 한미은행 전 지점에서 가능하다."],
            ['title' => 'K-뷰티 미국 시장 점유율 급상승, 한인 유통업체 수혜', 'summary' => '한국 화장품의 미국 시장 점유율이 사상 최고치를 기록했다. 한인 유통업체와 온라인 판매 플랫폼이 큰 수혜를 보고 있다.', 'category' => '경제', 'content' => "한국 화장품의 미국 시장 점유율이 8.5%를 기록하며 사상 최고치를 달성했다. 이는 전년 대비 2.3%p 상승한 수치로, 프랑스에 이어 2위를 차지했다.\n\n특히 선크림, 세럼, 시트마스크 등 스킨케어 카테고리에서 한국 제품의 인기가 높다. 아마존과 세포라에서 K-뷰티 제품 매출이 전년 대비 45% 증가했다.\n\n한인 유통업체들은 이러한 트렌드의 최대 수혜자이다. LA 한인타운의 K-뷰티 전문 매장 수가 지난 2년간 2배로 늘었으며, 온라인 판매 플랫폼도 급성장하고 있다.\n\n업계 전문가들은 소셜미디어에서의 K-뷰티 콘텐츠 확산과 합리적인 가격 대비 높은 품질이 성공 요인이라고 분석했다."],

            // ── 생활 (교육, 건강, 음식) ──
            ['title' => 'LA 한국학교, 봄학기 등록 시작...한국어 교육 열기 뜨겁다', 'summary' => 'LA 지역 한국학교들이 봄학기 등록을 시작했다. 한인 2세, 3세 자녀들의 한국어 교육에 대한 관심이 높아지면서 등록 문의가 크게 증가했다.', 'category' => '생활', 'content' => "LA 지역 한국학교들이 봄학기 등록을 시작하면서 등록 문의가 전년 대비 30% 증가한 것으로 나타났다.\n\nK-드라마와 K-pop의 인기로 한인 2세, 3세뿐 아니라 비한인 학생들의 한국어 학습 수요도 크게 늘었다. 일부 한국학교는 비한인 학생 전용 반을 별도로 운영하고 있다.\n\n수업은 매주 토요일 오전에 진행되며, 한국어 읽기쓰기부터 한국 역사문화까지 다양한 과목이 개설되어 있다. 온라인 수업도 병행하여 원거리 학생들의 참여를 돕고 있다.\n\n한국학교 관계자는 한국어 교육이 단순한 언어 학습을 넘어 정체성 형성과 가족 간 소통에 중요한 역할을 한다고 강조했다."],
            ['title' => '한인 의료진, 무료 건강검진 행사 개최', 'summary' => '한인 의사회가 무보험 한인을 대상으로 무료 건강검진 행사를 개최한다. 혈압, 혈당, 콜레스테롤 검사 및 건강 상담을 무료로 제공한다.', 'category' => '생활', 'content' => "한인 의사회가 무보험 및 저소득 한인을 대상으로 대규모 무료 건강검진 행사를 개최한다. 이번 행사는 한인 커뮤니티 센터에서 이틀간 진행된다.\n\n제공되는 검진 항목은 혈압, 혈당, 콜레스테롤, BMI 측정, 시력 검사 등이며, 내과, 가정의학과, 안과, 치과 전문의 상담도 무료로 받을 수 있다.\n\n특히 올해는 정신건강 상담 부스가 추가되어 우울증과 불안 장애 관련 스크리닝도 실시한다. 이민 생활의 스트레스로 정신건강 문제를 겪는 한인이 늘어나고 있기 때문이다.\n\n한인 의사회장은 건강보험이 없어 병원 방문을 꺼리는 한인들이 많다며, 정기적인 건강검진의 중요성을 강조했다."],
            ['title' => '한인타운 새 맛집 탐방, 정통 전주비빔밥 전문점 오픈', 'summary' => '한인타운에 전주비빔밥 전문점이 새로 오픈했다. 전주에서 직접 공수한 재료로 정통 맛을 재현하고 있어 한인들 사이에서 입소문이 나고 있다.', 'category' => '생활', 'content' => "한인타운 올림픽 블러바드에 전주비빔밥 전문점이 새로 문을 열어 한인 미식가들의 관심을 끌고 있다.\n\n이 식당은 전주에서 직접 공수한 육회, 고추장, 콩나물 등 핵심 재료를 사용하며, 돌솥비빔밥과 회비빔밥 등 10여 가지 비빔밥 메뉴를 선보이고 있다.\n\n오픈 첫 주부터 긴 대기줄이 생기며 입소문이 퍼지고 있다. 가격은 12~18달러 선으로 한인타운 다른 한식당과 비슷한 수준이다.\n\n식당 대표는 미국에서도 한국 현지의 맛을 그대로 느낄 수 있도록 모든 재료를 직접 선별하고 있다며, 앞으로 전주 콩나물국밥 등 전주 대표 음식 메뉴도 추가할 계획이라고 밝혔다."],
            ['title' => 'SAT 시험 대비, 한인 학원가 특강 시즌 돌입', 'summary' => '봄 SAT 시험을 앞두고 한인 학원가가 특강 시즌에 돌입했다. 온라인 수업과 병행하는 하이브리드 수업 방식이 인기를 끌고 있다.', 'category' => '생활', 'content' => "봄 SAT 시험을 앞두고 LA와 뉴욕 한인 학원가가 특강 시즌에 돌입했다. 올해부터 적용되는 디지털 SAT에 맞춘 집중 대비 과정이 인기를 끌고 있다.\n\n한인 학원들은 온라인과 오프라인을 병행하는 하이브리드 수업 방식을 도입하여 학생들의 선택 폭을 넓혔다. 특히 AI 기반 맞춤형 학습 프로그램을 도입한 학원이 학부모들 사이에서 주목받고 있다.\n\n한인 교육 전문가는 디지털 SAT는 기존 종이 시험과 문제 유형이 다르므로, 새로운 형식에 맞는 준비가 필요하다고 조언했다.\n\n한편 일부 대학들이 SAT 점수 제출을 선택사항으로 유지하고 있지만, 명문대 입시에서는 여전히 높은 점수가 유리하다는 것이 전문가들의 의견이다."],
            ['title' => '한인 시니어센터, 치매 예방 프로그램 확대 운영', 'summary' => '한인 시니어센터가 치매 예방을 위한 두뇌 활동 프로그램을 확대 운영한다. 바둑, 장기, 한글 서예 등 다양한 활동이 마련되어 있다.', 'category' => '생활', 'content' => "한인 시니어센터가 치매 예방을 위한 다양한 두뇌 활동 프로그램을 확대 운영한다고 발표했다.\n\n새로 추가된 프로그램에는 바둑, 장기, 한글 서예, 퍼즐 맞추기, 기억력 게임 등이 포함된다. 또한 주 2회 전문 강사가 진행하는 치매 예방 체조 프로그램도 신설되었다.\n\n한인 노인 의학 전문의는 규칙적인 두뇌 활동이 치매 발병 위험을 최대 40%까지 낮출 수 있다며, 사회적 교류와 결합된 활동이 특히 효과적이라고 설명했다.\n\n시니어센터 관계자는 독거 한인 노인들이 집에서 혼자 시간을 보내는 것보다 센터에서 함께 활동하는 것이 정신건강에 훨씬 유익하다고 강조했다."],
            ['title' => '한인 교회, 무료 ESL 클래스 개설...이민자 영어 교육 지원', 'summary' => '지역 한인 교회가 새 이민자를 위한 무료 ESL 클래스를 개설했다. 초급부터 중급까지 다양한 레벨의 수업을 주 3회 제공한다.', 'category' => '생활', 'content' => "지역 한인 교회가 새 이민자를 위한 무료 ESL(English as a Second Language) 클래스를 개설하여 좋은 반응을 얻고 있다.\n\n수업은 초급, 초중급, 중급 3개 레벨로 나뉘어 주 3회(월, 수, 금) 오전 10시부터 정오까지 진행된다. 강사는 TESOL 자격을 갖춘 한인 자원봉사자들이다.\n\n교회 측은 영어 능력 부족이 이민 생활의 가장 큰 장벽 중 하나라며, 종교와 관계없이 모든 한인에게 수업을 개방하고 있다고 밝혔다.\n\n현재 80명 이상의 한인이 수강하고 있으며, 생활 영어 회화, 병원 및 은행 이용 영어, 시민권 시험 준비 영어 등 실용적인 내용 위주로 구성되어 있다."],
            ['title' => '한인 요리사, 미국 요리 경연 대회 결승 진출', 'summary' => '한인 셰프가 유명 미국 요리 경연 프로그램 결승에 진출했다. 한식의 세계화를 위해 노력해온 그의 도전이 한인 사회의 큰 응원을 받고 있다.', 'category' => '생활', 'content' => "한인 셰프가 미국의 유명 요리 경연 프로그램 결승에 진출하여 한인 사회의 뜨거운 응원을 받고 있다.\n\n그는 한식 기법을 현대적으로 재해석한 퓨전 요리로 심사위원들의 극찬을 받았다. 특히 고추장 글레이즈를 활용한 BBQ 요리와 김치 리소또가 높은 평가를 받았다.\n\n한인 셰프는 인터뷰에서 어머니에게 배운 한식 요리가 자신의 요리 철학의 뿌리라며, 한식의 다양한 맛과 건강한 발효 기법을 세계에 알리고 싶다고 포부를 밝혔다.\n\n결승전은 다음 주 방송될 예정이며, 한인 커뮤니티에서는 단체 응원 시청 행사도 계획하고 있다."],
            ['title' => '겨울철 독감 유행, 한인 커뮤니티 무료 예방접종 실시', 'summary' => '한인 건강재단이 독감 시즌을 맞아 무료 예방접종 캠페인을 실시한다. 65세 이상 한인 시니어와 어린이를 우선 대상으로 진행된다.', 'category' => '생활', 'content' => "한인 건강재단이 독감 시즌을 맞아 한인 커뮤니티를 대상으로 무료 독감 예방접종 캠페인을 실시한다.\n\n예방접종은 한인 커뮤니티 센터, 교회, 시니어센터 등 10개 장소에서 순차적으로 진행된다. 65세 이상 시니어와 6개월 이상 어린이가 우선 대상이다.\n\n올해 독감 시즌은 예년보다 일찍 시작되어 이미 많은 환자가 발생하고 있다. 한인 의사회는 예방접종이 독감 예방의 가장 효과적인 방법이라며 적극적인 접종을 권유했다.\n\n보험이 없는 한인도 무료로 접종받을 수 있으며, 별도의 예약 없이 현장 방문으로 접종이 가능하다."],
            ['title' => '한인 대학생, 아이비리그 합격률 역대 최고', 'summary' => '올해 아이비리그 대학 입시에서 한인 학생들의 합격률이 역대 최고치를 기록했다. 특히 공학과 컴퓨터 과학 분야에서 두각을 나타냈다.', 'category' => '생활', 'content' => "올해 아이비리그 대학 입시 결과에서 한인 학생들의 합격률이 역대 최고치를 기록한 것으로 나타났다.\n\n한인 교육 단체의 조사에 따르면, 올해 아이비리그 8개 대학에 합격한 한인 학생 수는 약 850명으로, 전년 대비 12% 증가했다. 특히 MIT, 스탠퍼드 등 명문 공과대학에서도 한인 합격자가 크게 늘었다.\n\n합격자들의 주요 전공 희망 분야는 컴퓨터 과학(CS), 생물공학, 경제학 순이었다. 과외 활동에서는 연구 프로젝트 참여와 커뮤니티 봉사 활동이 두드러졌다.\n\n교육 전문가들은 한인 학생들의 학업 역량이 전반적으로 향상되었으며, 대학 입시 전략도 더욱 체계화되었다고 분석했다."],
            ['title' => '한인 커뮤니티 텃밭 프로그램, 봄 참가자 모집', 'summary' => '한인 커뮤니티 센터가 봄 텃밭 프로그램 참가자를 모집한다. 고추, 깻잎, 상추 등 한국 채소를 직접 재배할 수 있어 매년 인기가 높다.', 'category' => '생활', 'content' => "한인 커뮤니티 센터가 봄 텃밭 프로그램 참가자를 모집한다. 올해로 8년째를 맞는 이 프로그램은 매년 높은 인기로 조기 마감된다.\n\n참가자에게는 4x8피트 크기의 텃밭 공간이 배정되며, 고추, 깻잎, 상추, 부추, 호박 등 한국 채소 씨앗과 모종이 무료로 제공된다.\n\n텃밭 프로그램은 단순한 재배 활동을 넘어 한인 이웃 간의 소통과 교류의 장이 되고 있다. 참가자들은 서로 재배 노하우를 공유하고 수확물을 나누며 커뮤니티 유대를 강화하고 있다.\n\n참가비는 시즌당 50달러이며, 65세 이상 시니어는 무료이다. 신청은 한인 커뮤니티 센터 웹사이트에서 가능하다."],
            ['title' => '한인 어린이집 인가 기준 강화, 학부모 반응 엇갈려', 'summary' => '캘리포니아 주정부가 어린이집 인가 기준을 강화하면서 한인 어린이집들이 시설 개선에 나서고 있다. 학부모들의 반응은 안전 강화에 긍정적이지만 비용 인상 우려도 있다.', 'category' => '생활', 'content' => "캘리포니아 주정부가 어린이집 인가 기준을 대폭 강화하면서 한인 어린이집들이 시설 개선에 분주하게 나서고 있다.\n\n새 기준에는 교사 대 아동 비율 축소, 실외 놀이 공간 확대, CCTV 설치 의무화, 교사 자격 요건 강화 등이 포함되어 있다.\n\n한인 학부모들의 반응은 엇갈리고 있다. 아이들의 안전이 강화되는 것은 환영하지만, 이에 따른 보육료 인상이 부담된다는 의견이 많다. 월 보육료가 평균 200~300달러 인상될 것으로 예상된다.\n\n한인 보육 연합회는 정부의 보육 보조금 확대를 요청하는 한편, 한인 어린이집 운영자들을 위한 시설 개선 컨설팅도 제공하고 있다."],
            ['title' => '한인 약사, 건강보조제 올바른 복용법 안내', 'summary' => '한인 약사회가 한인들이 즐겨 찾는 건강보조제의 올바른 복용법을 안내했다. 특히 한약과 양약의 병용 시 주의사항에 대해 강조했다.', 'category' => '생활', 'content' => "한인 약사회가 한인들이 즐겨 복용하는 건강보조제의 올바른 복용법에 대한 안내 캠페인을 시작했다.\n\n한인들 사이에서 인기 있는 오메가3, 비타민D, 프로바이오틱스, 홍삼 등의 건강보조제가 처방약과 상호작용을 일으킬 수 있어 주의가 필요하다고 경고했다.\n\n특히 한약과 양약을 함께 복용하는 한인들이 많은데, 이 경우 간 기능에 부담을 줄 수 있으므로 반드시 약사나 의사와 상담한 후 복용해야 한다고 강조했다.\n\n한인 약사회는 매월 첫째 토요일에 무료 약물 상담 서비스를 제공하며, 복용 중인 모든 약과 보조제를 가지고 방문하면 상호작용 여부를 확인해준다."],
            ['title' => '한인타운 떡볶이 대전, 20개 업체 참가', 'summary' => '한인타운에서 떡볶이 맛 대결 행사가 열린다. 20개 업체가 참가하여 각자의 비법 떡볶이를 선보이며, 방문객 투표로 최고의 떡볶이를 선정한다.', 'category' => '생활', 'content' => "한인타운에서 제3회 떡볶이 맛 대결 행사가 열린다. 올해는 역대 최다인 20개 업체가 참가하여 각자의 비법 떡볶이를 선보인다.\n\n참가 업체들은 전통 떡볶이부터 치즈 떡볶이, 해물 떡볶이, 크림 떡볶이 등 다양한 창작 떡볶이를 준비하고 있다. 입장권 가격에 5가지 떡볶이 시식이 포함되어 있다.\n\n방문객 투표와 전문 심사위원 평가를 합산하여 최고의 떡볶이를 선정하며, 우승 업체에는 상금 5,000달러와 트로피가 수여된다.\n\n지난해 행사에는 3,000여 명이 방문하여 큰 호응을 얻었으며, 올해는 5,000명 이상의 방문객이 예상된다. 비한인 방문객 비율도 30%에 달해 한식의 인기를 실감케 한다."],

            // ── 문화 (K-pop, 드라마, 한류) ──
            ['title' => 'BTS 진, 미국 솔로 투어 LA 공연 매진', 'summary' => 'BTS 멤버 진의 미국 솔로 투어 LA 공연이 매진되었다. 한인 팬들뿐 아니라 다양한 인종의 팬들이 공연장을 가득 메울 예정이다.', 'category' => '문화', 'content' => "BTS 멤버 진의 첫 미국 솔로 투어 중 LA 공연이 티켓 오픈 즉시 매진되었다. 1만 5천 석 규모의 공연장이 순식간에 채워졌다.\n\n이번 LA 공연은 미국 투어 6개 도시 중 유일하게 2회 연속 공연으로 확대되었으며, 추가 공연도 빠르게 매진되었다.\n\n한인 팬들뿐 아니라 히스패닉, 백인, 흑인 등 다양한 인종의 팬들이 티켓을 구매하여, K-pop이 인종을 초월한 글로벌 문화 현상임을 다시 한번 입증했다.\n\n공연 전날에는 한인타운에서 팬 미팅 이벤트도 예정되어 있으며, 한인 상점들은 BTS 관련 특별 할인 행사를 준비하고 있다."],
            ['title' => '넷플릭스 신작 한국 드라마, 미국 시청률 1위 달성', 'summary' => '넷플릭스에서 공개된 새 한국 드라마가 미국 내 시청률 1위를 기록했다. 한류 콘텐츠의 위상이 다시 한번 확인된 가운데, LA에서 팬미팅 행사도 예정되어 있다.', 'category' => '문화', 'content' => "넷플릭스에서 공개된 새 한국 드라마가 공개 첫 주에 미국 내 시청률 1위를 달성했다. 전 세계 비영어권 드라마 중에서도 최고 시청 시간을 기록했다.\n\n이 드라마는 한국의 재벌 가문을 배경으로 한 스릴러물로, 미국 평론가들로부터도 높은 평가를 받고 있다. 로튼토마토 신선도 95%를 기록 중이다.\n\n한류의 위상이 다시 한번 확인되면서, LA 한국문화원에서는 출연 배우들을 초청한 팬미팅 행사를 개최할 예정이다.\n\n한인 미디어 전문가는 한국 드라마가 미국 주류 엔터테인먼트 시장에서 확고한 입지를 구축했으며, 이는 한인 커뮤니티의 문화적 자부심을 높이고 있다고 분석했다."],
            ['title' => 'LA 한국문화원, 한복 체험 행사 개최', 'summary' => 'LA 한국문화원이 외국인과 한인 2세를 대상으로 한복 체험 행사를 개최한다. 한복 입기, 다도 체험, 전통 놀이 등 다양한 프로그램이 마련되어 있다.', 'category' => '문화', 'content' => "LA 한국문화원이 한국 전통 문화를 알리기 위한 한복 체험 행사를 개최한다. 이번 행사는 외국인과 한인 2세, 3세를 주요 대상으로 기획되었다.\n\n참가자들은 전통 한복을 직접 입어보고, 한복 사진 촬영, 다도 체험, 전통 놀이(윷놀이, 제기차기) 등 다양한 프로그램에 참여할 수 있다.\n\n한복 디자이너가 현장에서 한복의 역사와 의미를 설명하고, 현대적으로 재해석된 신한복 패션쇼도 진행된다.\n\n한국문화원장은 한복은 한국 문화의 아름다움을 가장 잘 보여주는 요소 중 하나이며, 많은 미국인들이 한복을 체험하고 한국 문화에 대한 관심을 높이길 바란다고 밝혔다."],
            ['title' => '한인 영화감독, 선댄스 영화제 심사위원 특별상 수상', 'summary' => '한인 2세 영화감독이 선댄스 영화제에서 심사위원 특별상을 수상했다. 한인 이민자 가족의 이야기를 다룬 이 영화는 비평가들의 호평을 받았다.', 'category' => '문화', 'content' => "한인 2세 영화감독이 선댄스 영화제에서 심사위원 특별상을 수상하며 한인 커뮤니티에 기쁜 소식을 전했다.\n\n수상작은 1980년대 LA에 정착한 한인 이민 가족의 애환과 성장을 그린 드라마로, 감독 자신의 가족 이야기에서 영감을 받았다.\n\n심사위원들은 이민자 경험을 보편적인 인간 이야기로 승화시킨 점과 배우들의 뛰어난 연기를 높이 평가했다. 주연 배우 역시 한인 2세로, 자신의 실제 경험을 연기에 녹여냈다.\n\n이 영화는 올 가을 극장 개봉이 예정되어 있으며, 이미 여러 배급사에서 러브콜을 보내고 있는 것으로 알려졌다."],
            ['title' => 'K-pop 그룹, 뉴욕 매디슨 스퀘어 가든 공연 확정', 'summary' => 'K-pop 걸그룹의 뉴욕 MSG 공연이 확정되었다. 동부 지역 한인 팬들의 기대감이 높아지고 있으며, 티켓 예매가 시작되자마자 빠르게 매진되고 있다.', 'category' => '문화', 'content' => "K-pop 걸그룹의 뉴욕 매디슨 스퀘어 가든(MSG) 단독 공연이 공식 확정되었다. MSG는 2만 석 규모의 세계적인 공연장으로 K-pop 그룹이 이 무대에 서는 것은 큰 의미가 있다.\n\n티켓 예매가 시작되자마자 빠르게 매진이 이어지고 있으며, 동부 지역 한인 팬들의 기대감이 높아지고 있다. 리셀 시장에서는 원가의 3~5배 가격에 거래되고 있다.\n\n공연 당일에는 MSG 인근에서 한인 팬 커뮤니티가 주최하는 응원봉 배포 및 포토존 이벤트도 진행될 예정이다.\n\n뉴욕 한인 문화단체는 이번 공연이 한류의 미국 동부 진출을 더욱 가속화할 것이라며 환영의 뜻을 밝혔다."],
            ['title' => '한인 미술작가, 뉴욕 갤러리 개인전 화제', 'summary' => '뉴욕에서 활동하는 한인 미술작가의 개인전이 화제를 모으고 있다. 한국 전통 미학과 현대 미술을 결합한 작품들이 미술계의 주목을 받고 있다.', 'category' => '문화', 'content' => "뉴욕 첼시 갤러리에서 열리고 있는 한인 미술작가의 개인전이 미술계에서 큰 화제를 모으고 있다.\n\n이번 전시에는 한국 전통 도자기의 곡선미와 현대 추상미술을 결합한 대형 설치 작품 20여 점이 전시되어 있다. 작가는 한국의 달항아리에서 영감을 받아 현대적 재해석을 시도했다.\n\n뉴욕타임스 미술평론가는 동양과 서양, 전통과 현대를 아우르는 독창적인 시각이 돋보인다고 평가했다.\n\n전시는 다음 달 말까지 계속되며, 무료로 관람할 수 있다. 한인 커뮤니티를 위한 한국어 도슨트 투어도 주말에 진행된다."],
            ['title' => '한류 박람회, 시카고에서 성황리 개최', 'summary' => '시카고에서 열린 한류 박람회에 3만 명 이상이 방문했다. K-pop 커버 댄스 대회, K-뷰티 체험, 한식 시식 등 다양한 한류 콘텐츠를 즐겼다.', 'category' => '문화', 'content' => "시카고에서 열린 제5회 한류 박람회가 3만 명 이상의 방문객을 기록하며 성황리에 마무리되었다.\n\n이번 박람회에서는 K-pop 커버 댄스 대회, K-뷰티 체험부스, 한식 시식 행사, 한국어 체험 코너 등 다양한 프로그램이 운영되었다. 특히 K-pop 커버 댄스 대회에는 200팀 이상이 참가하여 열띤 경쟁을 펼쳤다.\n\n방문객의 70% 이상이 비한인으로, 한류가 미국 중서부 지역에서도 큰 인기를 끌고 있음을 보여주었다.\n\n주최 측은 내년에는 규모를 더 확대하여 5일간의 축제로 기획하고 있다며, 한류를 통한 한미 문화 교류의 장을 더욱 발전시키겠다고 밝혔다."],
            ['title' => '한국 웹툰 기반 미국 드라마 제작 확정', 'summary' => '인기 한국 웹툰을 원작으로 한 미국 드라마 시리즈 제작이 확정되었다. 한인 프로듀서가 참여하여 원작의 감성을 살릴 계획이다.', 'category' => '문화', 'content' => "인기 한국 웹툰을 원작으로 한 미국 드라마 시리즈의 제작이 공식 확정되었다. 미국 주요 스트리밍 플랫폼에서 10부작으로 제작될 예정이다.\n\n한인 프로듀서가 총괄 프로듀서로 참여하여 원작 웹툰의 감성과 스토리라인을 최대한 살릴 계획이라고 밝혔다. 한국 원작자도 자문으로 참여한다.\n\n이번 제작으로 한국 웹툰의 글로벌 IP 가치가 더욱 부각되고 있다. 이미 여러 한국 웹툰이 할리우드에서 영화화되어 좋은 성과를 거두고 있다.\n\n한인 엔터테인먼트 업계 관계자는 한국 콘텐츠의 미국 진출이 드라마와 영화를 넘어 웹툰, 게임 등 다양한 분야로 확대되고 있다며 긍정적으로 전망했다."],
            ['title' => '미주 한인 문학상 시상식, 올해의 작가 선정', 'summary' => '미주 한인 문학상 시상식에서 올해의 작가가 선정되었다. 이민 생활의 애환을 담은 소설이 수상작으로 뽑혔다.', 'category' => '문화', 'content' => "제18회 미주 한인 문학상 시상식이 LA에서 열려 올해의 작가가 선정되었다. 수상작은 1세대 이민자 부부의 미국 정착기를 그린 장편소설이다.\n\n심사위원들은 이민 생활의 고달픔과 희망을 진솔하게 담아낸 문장력과, 한국어와 영어 사이에서 갈등하는 이민자의 정체성을 섬세하게 표현한 점을 높이 평가했다.\n\n수상 작가는 자신의 부모님의 이민 이야기에서 영감을 받았다며, 한인 이민자들의 이야기가 더 많이 기록되어야 한다고 소감을 밝혔다.\n\n시상식에는 200여 명의 한인 문학인과 독자들이 참석하여 한인 문학의 발전을 축하했다."],
            ['title' => 'K-드라마 팝업 카페, 한인타운에 한정 오픈', 'summary' => '인기 K-드라마를 테마로 한 팝업 카페가 한인타운에 한정 기간 오픈했다. 드라마 속 메뉴를 재현한 음료와 디저트가 큰 인기를 끌고 있다.', 'category' => '문화', 'content' => "인기 K-드라마를 테마로 한 팝업 카페가 한인타운에 2개월 한정으로 오픈하여 큰 인기를 끌고 있다.\n\n카페 내부는 드라마 속 세트장을 재현한 인테리어로 꾸며져 있으며, 드라마에 등장한 음료와 디저트를 그대로 맛볼 수 있다. 포토존도 설치되어 SNS 인증샷 명소로 떠오르고 있다.\n\n오픈 첫 주말에만 1,500명 이상이 방문했으며, 평일에도 30분 이상 대기가 필요한 상황이다. 방문객의 약 40%는 비한인으로, K-드라마의 폭넓은 팬층을 보여준다.\n\n카페 운영사는 반응이 좋을 경우 뉴욕과 시카고에서도 팝업을 열 계획이라고 밝혔다."],
            ['title' => '한국 전통 공연, 케네디센터 무대 오른다', 'summary' => '한국 전통 가무악 공연이 워싱턴DC 케네디센터에서 열린다. 판소리, 사물놀이, 부채춤 등 한국 전통 예술을 미국 관객에게 선보인다.', 'category' => '문화', 'content' => "한국 전통 가무악 공연이 워싱턴DC 케네디센터 테라스 극장에서 열린다. 이번 공연은 한국 국립국악원과 미국 한국문화원의 공동 기획으로 마련되었다.\n\n공연 프로그램에는 판소리, 사물놀이, 부채춤, 가야금 연주, 태평무 등 한국 전통 예술의 정수가 담겨 있다. 미국 관객의 이해를 돕기 위해 영어 해설도 함께 제공된다.\n\n케네디센터 관계자는 한국 전통 예술의 아름다움과 역동성이 미국 관객들에게 깊은 인상을 줄 것이라고 기대감을 표현했다.\n\n워싱턴DC 한인 사회에서는 단체 관람을 조직하고 있으며, 한인 2세 자녀들에게 한국 전통 문화를 접할 수 있는 좋은 기회라며 참여를 독려하고 있다."],
            ['title' => '한인 2세 작가, 뉴욕타임스 베스트셀러 등극', 'summary' => '한인 2세 작가의 소설이 뉴욕타임스 베스트셀러 목록에 올랐다. 한국계 미국인의 정체성을 탐구한 이 소설은 출간 직후부터 큰 반향을 일으켰다.', 'category' => '문화', 'content' => "한인 2세 작가의 데뷔 소설이 뉴욕타임스 소설 부문 베스트셀러 목록에 올라 한인 문학계에 새로운 역사를 썼다.\n\n이 소설은 한국계 미국인 여성이 어머니의 고국 한국을 방문하면서 가족의 숨겨진 역사를 발견하는 이야기로, 이민 2세대의 정체성 갈등을 깊이 있게 탐구하고 있다.\n\n출간 직후 뉴욕타임스, 워싱턴포스트 등 주요 매체에서 올해의 주목할 신인 작가로 선정되었으며, 여러 유명 북클럽의 추천 도서로 채택되었다.\n\n작가는 한인 2세로서 겪었던 언어와 문화 사이의 갈등이 소설의 근간이 되었다며, 비슷한 경험을 가진 독자들에게 위로가 되길 바란다고 말했다."],

            // ── 스포츠 ──
            ['title' => '김하성, 시범경기 3타수 2안타 맹활약', 'summary' => '메이저리그 시범경기에서 김하성이 3타수 2안타를 기록하며 시즌 개막에 대한 기대감을 높였다. 팀 관계자는 올 시즌 주전 유격수로 활약할 것으로 전망했다.', 'category' => '스포츠', 'content' => "메이저리그 시범경기에서 김하성이 3타수 2안타 1타점의 맹활약을 펼치며 시즌 개막에 대한 기대감을 한껏 높였다.\n\n이날 김하성은 첫 타석에서 좌전 안타를 기록한 데 이어, 3번째 타석에서는 적시 2루타를 날려 팀 승리에 기여했다. 수비에서도 안정적인 모습을 보여주었다.\n\n팀 감독은 김하성이 올 시즌 주전 유격수로 활약할 것이라고 확인하며, 그의 꾸준한 성장에 만족감을 표시했다.\n\n한인 야구 팬들은 SNS를 통해 뜨거운 응원을 보내고 있으며, LA 한인타운의 스포츠 바에서는 개막전 단체 관람 행사를 준비하고 있다."],
            ['title' => '손흥민, 프리미어리그 이번 시즌 10호 골 달성', 'summary' => '손흥민이 프리미어리그에서 이번 시즌 10호 골을 기록했다. 아시아 선수 최다 골 기록을 경신하며 한인 팬들의 환호를 받았다.', 'category' => '스포츠', 'content' => "손흥민이 프리미어리그 경기에서 이번 시즌 10호 골을 기록하며 아시아 선수 프리미어리그 통산 최다 골 기록을 경신했다.\n\n이날 손흥민은 후반 15분에 왼발 중거리 슛으로 결승골을 넣으며 팀의 2-1 역전승을 이끌었다. 이 골로 프리미어리그 통산 112골을 기록했다.\n\n경기 후 손흥민은 팬들의 응원에 감사하다며 시즌이 끝날 때까지 최선을 다하겠다고 소감을 밝혔다.\n\n미주 한인 축구 팬 커뮤니티에서는 새벽 시간에도 불구하고 단체 시청 행사를 열어 응원하고 있으며, 한인 스포츠 바에서는 손흥민 골 기념 할인 이벤트를 진행하고 있다."],
            ['title' => '한인 골프 선수, PGA 투어 우승 도전', 'summary' => '한인 골프 선수가 PGA 투어 대회에서 최종 라운드에 우승권에 진입했다. 한인 갤러리들의 뜨거운 응원 속에 마지막 홀까지 치열한 경쟁을 펼쳤다.', 'category' => '스포츠', 'content' => "한인 골프 선수가 PGA 투어 대회 최종 라운드에서 우승권에 진입하여 한인 갤러리들의 뜨거운 응원을 받았다.\n\n3라운드까지 공동 2위를 기록한 그는 최종 라운드에서 버디 6개를 잡으며 선두권을 유지했다. 마지막 18번 홀에서의 아쉬운 보기로 단독 우승에는 실패했지만 준우승을 차지했다.\n\n한인 골프 팬 수백 명이 현장에서 태극기를 흔들며 열띤 응원을 펼쳤다. 대회 관계자는 한인 갤러리의 열정적인 응원이 대회의 분위기를 한층 뜨겁게 했다고 전했다.\n\n이 선수는 다음 대회에서 반드시 우승 트로피를 들어올리겠다며 팬들에게 감사의 인사를 전했다."],
            ['title' => 'LPGA 한인 선수, 시즌 첫 우승 트로피 획득', 'summary' => 'LPGA 투어에서 한인 여자 골프 선수가 시즌 첫 우승을 차지했다. 마지막 날 역전에 성공하며 통산 5승째를 기록했다.', 'category' => '스포츠', 'content' => "LPGA 투어에서 한인 여자 골프 선수가 시즌 첫 우승 트로피를 들어올렸다. 최종 라운드에서 5타를 줄이며 극적인 역전승을 거두었다.\n\n이번 우승으로 LPGA 통산 5승을 달성했으며, 세계랭킹도 10위권 진입이 확실시되고 있다. 우승 상금은 45만 달러이다.\n\n선수는 우승 인터뷰에서 한인 팬들의 꾸준한 응원이 큰 힘이 되었다며, 올 시즌 더 많은 좋은 성적을 낼 수 있도록 노력하겠다고 포부를 밝혔다.\n\n한인 여자 골프 팬 커뮤니티에서는 축하 메시지가 쏟아지고 있으며, 다음 대회 현장 응원단도 조직되고 있다."],
            ['title' => '한인 청소년 야구팀, 전미 대회 준우승 쾌거', 'summary' => 'LA 한인 청소년 야구팀이 전미 리틀야구 대회에서 준우승을 차지했다. 한인 커뮤니티의 열정적인 응원이 큰 힘이 되었다고 선수들이 전했다.', 'category' => '스포츠', 'content' => "LA 한인 청소년 야구팀이 전미 리틀야구 대회에서 준우승이라는 쾌거를 이루었다. 12세 이하 부문에 출전한 이 팀은 6경기 중 5승 1패를 기록했다.\n\n결승전에서 아쉽게 석패했지만, 대회 기간 내내 뛰어난 팀워크와 투지를 보여주며 관중들의 큰 박수를 받았다. 팀의 에이스 투수는 대회 MVP 후보에도 올랐다.\n\n선수들은 한인 커뮤니티의 열정적인 응원이 큰 힘이 되었다며 감사의 뜻을 전했다. 학부모 응원단은 매 경기마다 현장에서 뜨거운 응원을 펼쳤다.\n\n팀을 이끄는 한인 코치는 이번 성과가 한인 청소년 체육 발전에 큰 의미가 있다며, 더 많은 한인 아이들이 야구를 즐기길 바란다고 말했다."],
            ['title' => '한인 태권도 도장, 미국 전국대회 금메달 석권', 'summary' => '한인이 운영하는 태권도 도장 소속 선수들이 전미 태권도 대회에서 금메달 5개를 석권했다. 한인 사범의 체계적인 훈련 방식이 주목받고 있다.', 'category' => '스포츠', 'content' => "한인 사범이 운영하는 태권도 도장 소속 선수들이 전미 태권도 대회에서 금메달 5개를 석권하는 놀라운 성과를 거두었다.\n\n품새와 겨루기 부문에서 모두 좋은 성적을 거두었으며, 특히 주니어 부문에서 3개의 금메달을 차지했다. 한인 선수뿐 아니라 비한인 제자들의 활약도 돋보였다.\n\n도장을 운영하는 김 사범은 한국식 체계적인 훈련 방법과 정신 수양을 결합한 교육이 성과의 비결이라고 설명했다.\n\n현재 이 도장에는 한인 학생 외에도 히스패닉, 백인, 흑인 학생 등 다양한 인종의 150여 명이 수련하고 있어, 태권도가 한국 문화를 알리는 중요한 매개체 역할을 하고 있다."],
            ['title' => 'MLB 개막전 한인 선수 라인업 확정', 'summary' => '2026 MLB 시즌 개막을 앞두고 한인 선수들의 라인업이 확정되었다. 올 시즌 메이저리그에서 뛰는 한인 선수는 총 5명으로, 역대 최다 타이 기록이다.', 'category' => '스포츠', 'content' => "2026 MLB 시즌 개막을 앞두고 한인 선수 5명의 개막전 로스터 등재가 확정되었다. 이는 역대 최다 타이 기록으로, 한인 야구의 저력을 보여주고 있다.\n\n김하성을 비롯한 5명의 한인 선수들은 각각의 팀에서 핵심 전력으로 활약할 것으로 기대된다. 특히 올해 신인으로 메이저리그에 데뷔하는 한인 투수에 대한 관심이 높다.\n\n한인 야구 전문 미디어는 올 시즌 한인 선수들의 활약을 실시간으로 전달할 계획이며, 한국어 팟캐스트도 운영할 예정이다.\n\n한인타운 스포츠 바에서는 개막전 단체 관람 행사를 준비하고 있으며, 한인 선수 경기일에는 특별 할인도 진행한다."],
            ['title' => '한인 마라톤 클럽, 보스턴 마라톤 완주 도전', 'summary' => '한인 마라톤 클럽 회원 30명이 보스턴 마라톤에 참가한다. 한인 커뮤니티를 대표하여 함께 달리는 것에 큰 의미를 두고 있다고 밝혔다.', 'category' => '스포츠', 'content' => "한인 마라톤 클럽 회원 30명이 올해 보스턴 마라톤에 참가한다. 이는 한인 마라톤 클럽 역사상 최다 참가 인원이다.\n\n보스턴 마라톤은 세계 6대 메이저 마라톤 중 하나로, 참가 자격 기준이 까다로운 것으로 유명하다. 30명 전원이 자격 기준(BQ)을 통과하여 출전권을 획득했다.\n\n클럽 대표는 한인 커뮤니티를 대표하여 함께 달리는 것에 큰 의미를 두고 있다며, 완주를 통해 한인의 도전 정신을 보여주겠다고 포부를 밝혔다.\n\n클럽은 매주 토요일 새벽 한인타운에서 함께 훈련하고 있으며, 자선 기금 모금도 병행하여 한인 장학금 재단에 기부할 계획이다."],
            ['title' => '한인 UFC 선수, 타이틀전 도전권 획득', 'summary' => '한인 UFC 선수가 인상적인 KO 승리를 거두며 타이틀전 도전권을 획득했다. 한인 최초의 UFC 챔피언 탄생에 대한 기대가 높아지고 있다.', 'category' => '스포츠', 'content' => "한인 UFC 선수가 라스베이거스에서 열린 UFC 대회에서 인상적인 2라운드 KO 승리를 거두며 타이틀전 도전권을 획득했다.\n\n이번 승리로 MMA 전적 15승 2패를 기록하며 체급 랭킹 1위에 올랐다. UFC 대표는 다음 타이틀전 도전자로 그를 공식 지명했다.\n\n한인 최초의 UFC 챔피언 탄생 가능성에 한인 격투기 팬들의 기대가 한껏 높아지고 있다. 한인타운에서는 타이틀전 당일 대형 스크린 관람 행사가 계획되고 있다.\n\n선수는 한인 커뮤니티에서 배운 정신력과 끈기가 성공의 비결이라며, 챔피언 벨트를 반드시 한인 커뮤니티에 바치겠다고 다짐했다."],
            ['title' => '한인 여자 배구 선수, 미국 프로리그 MVP 수상', 'summary' => '한인 여자 배구 선수가 미국 프로배구 리그에서 시즌 MVP를 수상했다. 뛰어난 기량과 리더십으로 팀을 플레이오프에 이끈 공로를 인정받았다.', 'category' => '스포츠', 'content' => "한인 여자 배구 선수가 미국 프로배구 리그(PVL)에서 시즌 MVP를 수상하는 영예를 안았다.\n\n이번 시즌 경기당 평균 22.5점을 기록하며 리그 득점 1위를 차지한 그녀는, 뛰어난 기량과 리더십으로 팀을 정규 시즌 2위이자 플레이오프에 이끈 공로를 인정받았다.\n\n수상 소감에서 한인 부모님의 헌신적인 지원에 감사하다며, 한인 여자 선수들도 미국 프로 스포츠에서 충분히 성공할 수 있다는 것을 보여주고 싶었다고 밝혔다.\n\n한인 체육회는 그녀의 수상을 축하하며, 한인 청소년 체육 장학금 수여 행사에 특별 게스트로 초청할 계획이다."],

            // ── 기타 (커뮤니티, 종교, 문화행사) ──
            ['title' => '한인 교회 연합, 추수감사절 불우이웃 돕기 행사', 'summary' => '한인 교회 연합이 추수감사절을 맞아 불우이웃 돕기 행사를 진행한다. 식료품 기부와 무료 식사 제공 등 나눔 활동이 이어질 예정이다.', 'category' => '기타', 'content' => "한인 교회 연합이 추수감사절을 맞아 대규모 불우이웃 돕기 행사를 진행한다. 올해로 12년째를 맞는 이 행사는 한인 커뮤니티의 대표적인 나눔 활동이다.\n\n행사에서는 500가정에 터키와 식료품 박스를 배포하고, 독거 노인과 저소득 가정을 위한 무료 추수감사절 만찬도 제공한다.\n\n한인 교회 연합 대표는 추수감사절의 진정한 의미는 나눔에 있다며, 어려운 이웃을 돕는 데 한인 커뮤니티가 앞장서고 있다고 말했다.\n\n자원봉사자 200명 이상이 참여할 예정이며, 식료품 기부는 한인 마트 3곳에 설치된 기부함을 통해 가능하다."],
            ['title' => '한인 봉사단체, 홈리스 한인 지원 프로그램 시작', 'summary' => '한인 봉사단체가 홈리스 상태에 놓인 한인들을 위한 종합 지원 프로그램을 시작한다. 임시 주거, 취업 알선, 정신건강 상담 등을 제공한다.', 'category' => '기타', 'content' => "한인 봉사단체가 홈리스 상태에 놓인 한인들을 위한 종합 지원 프로그램을 시작했다. LA와 뉴욕 지역에서 우선 시행된다.\n\n프로그램은 임시 주거 제공, 취업 알선, 정신건강 상담, 약물 중독 치료 연계, 법률 지원 등을 포함한다. 한국어로 서비스가 제공되어 언어 장벽 없이 도움을 받을 수 있다.\n\n단체 관계자는 한인 홈리스 인구가 알려진 것보다 훨씬 많다며, 사업 실패, 가정 해체, 정신건강 문제 등이 주요 원인이라고 설명했다.\n\n지원을 원하는 한인은 핫라인 전화 또는 한인 커뮤니티 센터를 통해 프로그램에 참여할 수 있다."],
            ['title' => '한인회 신년 하례식, 500여 명 참석 성황', 'summary' => '지역 한인회 신년 하례식에 500여 명의 한인이 참석하여 성황을 이루었다. 새해 덕담과 함께 올해 한인 커뮤니티 발전 방향을 논의했다.', 'category' => '기타', 'content' => "지역 한인회가 주최한 신년 하례식에 500여 명의 한인이 참석하여 성황을 이루었다. 행사는 한인타운의 대형 연회장에서 진행되었다.\n\n한인회장은 새해 인사에서 올해 한인 커뮤니티의 정치적 참여 확대, 차세대 리더십 양성, 한인 상권 활성화를 3대 핵심 과제로 제시했다.\n\n하례식에는 지역 시의원, 경찰서장, 교육위원 등 주류 사회 인사들도 참석하여 한인 커뮤니티와의 협력 의지를 밝혔다.\n\n참석자들은 전통 떡국을 나누어 먹으며 새해 덕담을 나누었고, 한복 패션쇼와 K-pop 공연 등 문화 행사도 함께 진행되어 즐거운 시간을 보냈다."],
            ['title' => '한인 노인회, 봄꽃놀이 행사 참가자 모집', 'summary' => '한인 노인회가 봄꽃놀이 행사 참가자를 모집한다. 워싱턴DC 벚꽃 축제 관람과 함께 한인 시니어들의 친목 도모를 위한 프로그램이 마련되어 있다.', 'category' => '기타', 'content' => "한인 노인회가 봄꽃놀이 행사 참가자를 모집하고 있다. 올해 행사는 워싱턴DC 벚꽃 축제 관람과 인근 한국전 참전 기념관 방문으로 구성된다.\n\n2박 3일 일정으로 진행되며, 왕복 버스, 숙박, 식사가 포함된 참가비는 1인당 150달러이다. 65세 이상 한인 시니어가 참가 대상이다.\n\n노인회 관계자는 집에서 혼자 지내는 시간이 많은 한인 시니어들에게 친목 도모와 외출의 좋은 기회가 될 것이라고 말했다.\n\n매년 인기가 높아 조기 마감되므로 관심 있는 분들의 빠른 신청을 권장하고 있다. 신청은 한인 노인회 사무실에서 직접 또는 전화로 가능하다."],
            ['title' => '한인 입양아 모임, 한국 문화 체험 캠프 개최', 'summary' => '한인 입양아들의 모임에서 한국 문화 체험 캠프를 개최한다. 한국어 기초, 전통 놀이, 한식 만들기 등을 통해 뿌리를 찾는 시간을 가진다.', 'category' => '기타', 'content' => "한인 입양아 모임이 한국 문화 체험 캠프를 개최하여 참가자들에게 뿌리를 찾는 기회를 제공한다. 올해로 10회째를 맞는 이 캠프는 전국에서 80여 명의 한인 입양인이 참가한다.\n\n3일간의 캠프 프로그램에는 한국어 기초 회화, 한식 만들기(김밥, 떡볶이), 전통 놀이 체험, 한복 입기, 사물놀이 배우기 등이 포함되어 있다.\n\n입양인 선배들의 경험 공유 세션과 한국 방문 프로그램 안내도 진행된다. 한국에서 친생 가족을 찾은 입양인의 감동적인 이야기도 공유된다.\n\n캠프 주최자는 한인 입양아들이 자신의 문화적 뿌리를 이해하고 자부심을 가질 수 있도록 돕는 것이 캠프의 목적이라고 밝혔다."],
            ['title' => '한인 자선 골프 대회, 장학금 기금 모금', 'summary' => '한인 자선 골프 대회가 열려 한인 학생 장학금 기금을 모금한다. 올해로 15회를 맞는 이 대회는 한인 커뮤니티의 대표적인 자선 행사로 자리잡았다.', 'category' => '기타', 'content' => "제15회 한인 자선 골프 대회가 열려 한인 대학생 장학금 기금을 모금한다. 올해 목표 모금액은 10만 달러이다.\n\n대회에는 한인 기업인, 전문직 종사자 120명이 참가하며, 경기 후에는 만찬과 자선 경매도 진행된다. 경매에는 한국 왕복 비행기 티켓, 골프 용품, 명품 등이 출품된다.\n\n지난 14년간 이 대회를 통해 총 85만 달러의 장학금이 모금되었으며, 300여 명의 한인 학생이 장학금을 받았다.\n\n대회 위원장은 한인 커뮤니티의 미래인 젊은이들의 교육을 지원하는 것이 가장 가치 있는 투자라며, 많은 한인들의 참여를 독려했다."],
            ['title' => '한인 타운 설날 행사, 전통 세시풍속 체험', 'summary' => '한인타운에서 설날 맞이 행사가 열린다. 윷놀이, 널뛰기, 떡국 나눔 등 전통 세시풍속을 체험할 수 있어 가족 단위 방문객에게 인기다.', 'category' => '기타', 'content' => "한인타운에서 설날 맞이 대규모 행사가 열린다. 한인 커뮤니티 센터 주관으로 이틀간 진행되는 이 행사는 한국 전통 세시풍속을 체험할 수 있는 기회를 제공한다.\n\n윷놀이 대회, 널뛰기 체험, 연날리기, 투호 던지기 등 전통 놀이와 함께, 무료 떡국 나눔 행사도 진행된다. 2,000인분의 떡국이 준비되어 있다.\n\n어린이를 위한 한복 체험 부스와 세배하기 프로그램도 마련되어 있어 가족 단위 방문객에게 특히 인기가 높다.\n\n행사 관계자는 설날 행사가 한인 2세, 3세 자녀들에게 한국 전통 문화를 전수하는 중요한 기회이며, 비한인 이웃들과 문화를 나누는 장이 되고 있다고 말했다."],
            ['title' => '한인 사진작가 모임, 커뮤니티 사진전 개최', 'summary' => '한인 아마추어 사진작가 모임이 커뮤니티 사진전을 개최한다. 한인 이민 생활의 다양한 순간을 담은 작품 50여 점이 전시된다.', 'category' => '기타', 'content' => "한인 아마추어 사진작가 모임이 제4회 커뮤니티 사진전을 개최한다. 이번 전시 주제는 '우리의 이야기(Our Story)'로, 한인 이민 생활의 다양한 순간을 담은 작품 50여 점이 전시된다.\n\n참여 작가 20명은 한인 마트의 아침 풍경, 한국학교의 아이들, 교회 할머니들의 기도, 한인타운 거리의 밤 등 일상적이지만 의미 있는 순간들을 카메라에 담았다.\n\n전시는 한인 커뮤니티 센터 갤러리에서 2주간 진행되며, 무료로 관람할 수 있다.\n\n모임 대표는 전문 사진작가가 아닌 일반 한인들의 시선으로 포착한 이민 생활의 모습이 더욱 진솔하고 감동적이라며, 많은 한인의 관람을 기대한다고 밝혔다."],
            ['title' => '한인 동물보호 단체, 유기견 입양 행사 진행', 'summary' => '한인 동물보호 단체가 유기견 입양 행사를 진행한다. 한인 가정에서 버려진 반려견을 새 가족에게 연결해주는 프로그램이다.', 'category' => '기타', 'content' => "한인 동물보호 단체가 한인 가정에서 유기된 반려견을 새 가족에게 연결해주는 입양 행사를 진행한다.\n\n현재 단체에서 보호 중인 유기견 30마리가 입양 대기 중이며, 소형견부터 중대형견까지 다양한 품종이 있다. 모두 건강검진과 중성화 수술이 완료된 상태이다.\n\n입양 신청자에게는 기본 사료와 간식, 반려견 용품 세트가 무료로 제공된다. 단 입양 전 가정 방문 확인과 입양 서약서 작성이 필요하다.\n\n단체 관계자는 한국으로의 귀국이나 이사 등으로 반려견을 버리는 한인 가정이 늘고 있다며 책임감 있는 반려 문화를 당부했다."],
            ['title' => '한인 청년회, 멘토링 프로그램 참가자 모집', 'summary' => '한인 청년회가 한인 고등학생을 대상으로 한 멘토링 프로그램 참가자를 모집한다. 대학 진학, 커리어 상담, 리더십 훈련 등을 제공한다.', 'category' => '기타', 'content' => "한인 청년회가 한인 고등학생을 대상으로 한 멘토링 프로그램 참가자를 모집하고 있다. 올해로 8회째를 맞는 이 프로그램은 한인 차세대 리더 양성을 목표로 한다.\n\n프로그램은 6개월 과정으로, 대학 진학 상담, 커리어 탐색, 리더십 훈련, 커뮤니티 봉사 프로젝트 등으로 구성되어 있다. 각 학생에게 한인 전문직 종사자가 1:1 멘토로 배정된다.\n\n지난 7년간 이 프로그램을 수료한 학생 중 90% 이상이 4년제 대학에 진학했으며, 다수가 장학금을 받았다.\n\n청년회 대표는 한인 고등학생들이 대학과 진로에 대한 고민을 나눌 수 있는 선배가 있다는 것만으로도 큰 도움이 된다며, 많은 참여를 독려했다."],
            ['title' => '한인 워킹맘 네트워크, 육아 고민 나눔 모임', 'summary' => '한인 워킹맘들을 위한 네트워크 모임이 정기적으로 열리고 있다. 미국에서의 육아 고민을 나누고 정보를 교환하는 따뜻한 커뮤니티가 형성되고 있다.', 'category' => '기타', 'content' => "한인 워킹맘들을 위한 네트워크 모임이 매월 정기적으로 열리며 큰 호응을 얻고 있다. 현재 회원 수가 300명을 넘어섰다.\n\n모임에서는 미국에서의 육아 고민, 직장과 가정의 양립, 아이 교육 정보 등을 나누고 있다. 온라인 카카오톡 그룹과 오프라인 모임을 병행하여 활발한 소통이 이루어지고 있다.\n\n최근에는 소아과 의사, 교육 전문가, 이민 변호사 등을 초청한 전문가 강연도 진행하고 있다. 아이 돌봄 공유 서비스도 자체적으로 운영하고 있다.\n\n네트워크 창립자는 미국에서 아이를 키우는 한인 엄마들이 느끼는 외로움과 어려움을 함께 나누고 해결해나가는 것이 모임의 가장 큰 의미라고 말했다."],
            ['title' => '한인 역사관, 이민 100주년 특별 전시 개관', 'summary' => '한인 역사관이 한인 미국 이민 역사를 조명하는 특별 전시를 개관했다. 초기 이민자들의 사진과 유품, 구술 기록 등이 전시되어 있다.', 'category' => '기타', 'content' => "한인 역사관이 한인 미국 이민 100주년을 기념하는 특별 전시를 개관했다. 전시는 1903년 하와이 사탕수수 농장 이민부터 현재까지의 한인 이민 역사를 조명한다.\n\n전시실에는 초기 이민자들의 사진, 여권, 편지, 생활 용품 등 귀중한 유품과 함께 100여 명의 이민자 구술 기록이 영상으로 재생되고 있다.\n\n특히 LA 폭동 당시 한인 상인들의 경험을 다룬 코너와 K-pop을 통한 한류 확산을 보여주는 현대사 코너가 관람객들의 큰 관심을 끌고 있다.\n\n역사관장은 한인 이민 역사는 도전과 극복의 역사이며, 이 전시를 통해 한인 2세, 3세가 자신의 뿌리에 대한 자부심을 가지길 바란다고 밝혔다."],

            // ── 추가 기사 ──
            ['title' => '캘리포니아 산불 한인 피해 복구 지원 본격화', 'summary' => '최근 캘리포니아 산불로 피해를 입은 한인 가정에 대한 복구 지원이 본격화되었다. 한인회와 교회가 합동으로 긴급 구호품을 전달하고 있다.', 'category' => '기타', 'content' => "최근 캘리포니아 대형 산불로 피해를 입은 한인 가정에 대한 복구 지원이 본격화되고 있다. 현재까지 확인된 한인 피해 가정은 약 50가구이다.\n\n한인회와 교회가 합동으로 긴급 구호팀을 결성하여 식료품, 생필품, 의류 등을 전달하고 있다. 또한 임시 주거 지원과 FEMA 재난 지원금 신청을 돕는 한국어 상담도 진행 중이다.\n\n한인 보험 전문가들은 주택 보험 클레임 절차를 무료로 안내하고 있으며, 한인 변호사회도 법률 상담을 제공하고 있다.\n\n성금 모금도 활발하게 이루어지고 있어, 현재까지 한인 커뮤니티에서 약 15만 달러의 성금이 모금되었다."],
            ['title' => '한인 운전면허 시험 한국어 지원 확대', 'summary' => '캘리포니아 DMV가 운전면허 시험의 한국어 지원을 확대한다. 필기시험뿐 아니라 온라인 예약 시스템도 한국어로 이용할 수 있게 된다.', 'category' => '생활', 'content' => "캘리포니아 DMV가 운전면허 필기시험과 온라인 예약 시스템의 한국어 지원을 대폭 확대한다고 발표했다.\n\n기존에는 필기시험만 한국어로 응시할 수 있었으나, 이제 온라인 예약, 신청서 작성, 안내 자료 등도 한국어로 이용할 수 있게 된다.\n\n또한 한인 밀집 지역 DMV 사무소에는 한국어 통역 직원이 배치되어 대면 서비스도 한국어로 받을 수 있다.\n\n한인회 관계자는 영어가 불편한 한인 이민자들, 특히 고령 한인들의 운전면허 취득과 갱신이 훨씬 수월해질 것이라며 환영의 뜻을 밝혔다."],
            ['title' => '한인 치과의사회, 무료 치과 진료 봉사 실시', 'summary' => '한인 치과의사회가 저소득 한인을 대상으로 무료 치과 진료 봉사를 실시한다. 충치 치료, 스케일링, 발치 등 기본 치과 진료를 무료로 제공한다.', 'category' => '생활', 'content' => "한인 치과의사회가 저소득 및 무보험 한인을 대상으로 무료 치과 진료 봉사를 실시한다. 행사는 한인 커뮤니티 센터에서 이틀간 진행된다.\n\n제공되는 진료 항목은 구강 검진, 충치 치료, 스케일링, 발치, X-ray 촬영 등이다. 20명의 한인 치과의사가 자원봉사로 참여한다.\n\n치과 치료는 미국에서 가장 비용이 높은 의료 서비스 중 하나로, 보험이 없는 한인들이 치과 방문을 꺼리는 주요 원인이 되고 있다.\n\n치과의사회장은 구강 건강이 전신 건강에 큰 영향을 미치므로 정기적인 검진이 중요하다며, 이번 봉사를 통해 많은 한인이 혜택을 받길 바란다고 말했다."],
            ['title' => '트럼프 행정부 이민 정책 변화, 한인 사회 영향 분석', 'summary' => '새 행정부의 이민 정책 변화가 한인 사회에 미치는 영향을 전문가들이 분석했다. 취업 이민과 가족 초청 이민 분야에서 중요한 변화가 예상된다.', 'category' => '정치/사회', 'content' => "새 행정부의 이민 정책 변화가 한인 사회에 미치는 영향을 이민 전문가들이 분석했다. 취업 이민과 가족 초청 이민 분야에서 중요한 변화가 예상된다.\n\n전문가들은 취업이민 분야에서는 STEM 인력에 대한 우대가 강화될 것으로 보이며, 이는 IT 분야 한인 전문가들에게 유리하게 작용할 수 있다고 분석했다.\n\n반면 가족 초청 이민의 경우 형제자매 초청 카테고리의 축소 가능성이 제기되어 한인 사회에서 우려의 목소리가 나오고 있다.\n\n한인 이민변호사회는 정책 변화에 대한 정확한 정보를 전달하기 위해 무료 세미나를 개최하고, 개별 상황에 맞는 상담도 진행할 계획이다."],
            ['title' => '한인 IT 기업, 실리콘밸리 유니콘 등극 눈앞', 'summary' => '한인이 창업한 AI 스타트업이 최근 시리즈C 투자를 유치하며 기업가치 9억 달러를 달성했다. 유니콘 기업 등극이 목전에 다가왔다.', 'category' => '경제', 'content' => "한인이 창업한 AI 스타트업이 시리즈C 투자 라운드에서 1억 5천만 달러를 유치하며 기업가치 9억 달러를 달성했다. 유니콘(기업가치 10억 달러 이상) 등극이 목전에 다가왔다.\n\n이 스타트업은 AI 기반 기업용 문서 분석 솔루션을 개발하고 있으며, 포춘 500대 기업 중 50개 이상이 고객사이다. 연 매출 성장률은 200%를 기록하고 있다.\n\n창업자는 한국에서 KAIST를 졸업한 후 실리콘밸리에서 창업한 한인 1세대 기업가이다. 그는 한국의 기술력과 미국의 사업 환경이 결합되면 큰 시너지를 낼 수 있다고 강조했다.\n\n한인 벤처 커뮤니티에서는 이 스타트업의 유니콘 등극이 한인 창업 생태계에 큰 자극이 될 것이라며 기대감을 표했다."],
            ['title' => '한인 노래자랑 대회, 참가 신청 폭주', 'summary' => '제20회 미주 한인 노래자랑 대회의 참가 신청이 폭주하고 있다. 올해는 트로트 부문과 K-pop 부문으로 나누어 진행되며 우승 상금도 대폭 올랐다.', 'category' => '문화', 'content' => "제20회 미주 한인 노래자랑 대회의 참가 신청이 폭주하고 있다. 개최 20주년을 맞아 올해는 규모를 대폭 확대하여 진행된다.\n\n올해부터 트로트 부문과 K-pop 부문으로 나누어 진행되며, 각 부문 우승 상금이 기존 1,000달러에서 5,000달러로 대폭 인상되었다.\n\n참가 연령층도 10대부터 70대까지 다양하며, 예선은 LA, 뉴욕, 시카고 3개 지역에서 진행된다. 최종 결선은 LA 한인타운 대극장에서 열린다.\n\n대회 조직위원장은 노래자랑 대회가 20년간 한인 커뮤니티의 화합과 즐거움의 장이 되어왔다며, 올해도 많은 한인들의 참여와 관심을 부탁했다."],
            ['title' => '한인 2세 NBA 선수, 올스타전 출전 화제', 'summary' => '한인 2세 NBA 선수가 올스타전에 출전하여 화제를 모으고 있다. 아시안계 선수로는 이례적인 성과에 한인 커뮤니티의 자부심이 높아지고 있다.', 'category' => '스포츠', 'content' => "한인 2세 NBA 선수가 올스타전에 출전하여 한인 커뮤니티에 큰 화제를 불러일으키고 있다. 아시안계 선수의 NBA 올스타 출전은 역대 두 번째이다.\n\n이번 시즌 경기당 평균 24.3점, 7.2어시스트를 기록하며 리그 최고 가드 중 한 명으로 자리매김한 그는, 팬 투표에서도 높은 지지를 받아 올스타 선발 명단에 이름을 올렸다.\n\n한인 커뮤니티에서는 자부심이 한껏 높아지고 있다. 올스타전 당일에는 한인타운 곳곳에서 단체 관람 행사가 열릴 예정이다.\n\n선수는 한인 부모님의 교육과 격려가 성공의 원동력이라며, 한인 청소년들에게 꿈을 포기하지 말라는 메시지를 전했다."],
            ['title' => '미주 한인 재단, 대학 장학금 100명 선발', 'summary' => '미주 한인 재단이 올해 대학 장학금 수혜자 100명을 선발한다. 학업 성적과 봉사 활동, 리더십을 종합적으로 평가하여 선발할 예정이다.', 'category' => '생활', 'content' => "미주 한인 재단이 올해 대학 장학금 수혜자 100명을 선발한다고 발표했다. 장학금은 1인당 2,500~10,000달러이며, 총 규모는 50만 달러이다.\n\n신청 자격은 한인 또는 한국계 미국인 고등학교 졸업예정자 및 대학 재학생이다. 학업 성적(GPA 3.5 이상), 커뮤니티 봉사 활동, 리더십, 재정적 필요도를 종합적으로 평가한다.\n\n재단 이사장은 교육이 한인 커뮤니티 발전의 핵심이라며, 경제적 어려움으로 꿈을 포기하는 한인 학생이 없도록 장학금 규모를 매년 확대하고 있다고 밝혔다.\n\n신청은 재단 웹사이트에서 온라인으로 가능하며, 마감일은 다음 달 말이다."],
            ['title' => '한인타운 야시장, 매주 금요일 개장', 'summary' => '한인타운에 야시장이 매주 금요일 저녁에 열린다. 떡볶이, 호떡, 닭꼬치 등 한국 길거리 음식을 즐길 수 있어 젊은 층에게 특히 인기다.', 'category' => '생활', 'content' => "한인타운에 야시장이 매주 금요일 저녁 6시부터 11시까지 열려 큰 인기를 끌고 있다. 한국 길거리 음식과 문화를 즐길 수 있는 새로운 핫플레이스로 떠오르고 있다.\n\n떡볶이, 호떡, 닭꼬치, 김밥, 어묵, 타코야키 등 30여 개 부스에서 다양한 한국 길거리 음식을 판매한다. 가격은 대부분 5~12달러 선이다.\n\n음식 외에도 K-pop DJ 공연, 커버 댄스, 한국 인디 밴드 라이브 공연 등 문화 프로그램이 함께 운영된다. 한국식 포장마차 분위기를 재현한 소주바도 인기 코너이다.\n\n주최 측에 따르면 매주 평균 2,000명 이상이 방문하며, 방문객의 절반 이상이 비한인이라고 한다."],
            ['title' => '한인 변호사협회, 무료 법률 상담 제공', 'summary' => '한인 변호사협회가 이민, 부동산, 사업 관련 무료 법률 상담을 제공한다. 매월 첫째, 셋째 토요일에 한인 커뮤니티 센터에서 진행된다.', 'category' => '기타', 'content' => "한인 변호사협회가 한인 커뮤니티를 위한 무료 법률 상담 프로그램을 확대 운영한다. 상담은 매월 첫째, 셋째 토요일 오전 10시부터 오후 2시까지 진행된다.\n\n상담 분야는 이민법, 부동산, 사업법, 가정법, 형사법, 교통사고, 노동법 등 다양하다. 각 분야별 전문 한인 변호사 10여 명이 자원봉사로 참여한다.\n\n한인 변호사협회장은 법률 문제를 겪으면서도 비용 부담이나 언어 장벽으로 변호사 상담을 받지 못하는 한인이 많다며, 이 프로그램이 그런 분들에게 도움이 되길 바란다고 밝혔다.\n\n상담은 선착순으로 진행되며, 한인 커뮤니티 센터에서 당일 접수하면 된다."],
            ['title' => '한인 의류 디자이너, 뉴욕 패션위크 데뷔', 'summary' => '한인 의류 디자이너가 뉴욕 패션위크에 데뷔했다. 한복에서 영감을 받은 컬렉션이 패션 평론가들의 호평을 받았다.', 'category' => '문화', 'content' => "한인 의류 디자이너가 뉴욕 패션위크에 데뷔하며 한복에서 영감을 받은 컬렉션을 선보여 큰 주목을 받았다.\n\n컬렉션은 한복의 곡선미와 색감을 현대적 실루엣에 접목한 20벌의 작품으로 구성되었다. 특히 저고리의 깃과 소매 라인을 재해석한 재킷과 코트가 호평을 받았다.\n\n보그, 하퍼스 바자 등 주요 패션 매체에서 주목할 신인 디자이너로 선정되었으며, 여러 백화점에서 입점 제의가 들어오고 있다.\n\n디자이너는 한국 전통의 아름다움을 세계에 알리는 것이 꿈이었다며, 앞으로도 한국적 미학을 현대 패션에 녹여내는 작업을 계속하겠다고 포부를 밝혔다."],
            ['title' => '한인 양로원, 시설 확장 및 현대화 공사 착공', 'summary' => '한인 양로원이 증가하는 수요에 맞춰 시설 확장 및 현대화 공사에 착공했다. 100병상 규모로 확대되며 치매 전문 케어 유닛도 신설된다.', 'category' => '기타', 'content' => "LA 한인 양로원이 시설 확장 및 현대화 공사에 착공했다. 현재 60병상에서 100병상 규모로 확대되며, 공사 비용은 약 800만 달러이다.\n\n새 시설에는 치매 전문 케어 유닛, 재활 치료실, 한국식 목욕탕, 다목적 문화 공간 등이 신설된다. 한국 음식을 전문으로 하는 주방 시설도 확충된다.\n\n양로원 이사장은 한인 고령 인구가 빠르게 증가하면서 한국어로 서비스를 제공하는 양로 시설의 수요가 급증하고 있다고 설명했다.\n\n공사는 내년 하반기 완공 예정이며, 대기자 명단에 등록된 한인 시니어가 이미 200명을 넘어선 상태이다."],
            ['title' => '한국 영화, 미국 박스오피스 1000만 달러 돌파', 'summary' => '한국 액션 영화가 미국 박스오피스에서 1000만 달러를 돌파했다. 한인 관객뿐 아니라 주류 사회에서도 큰 반응을 얻고 있다.', 'category' => '문화', 'content' => "한국 액션 영화가 미국 박스오피스에서 1,000만 달러를 돌파하며 한국 영화의 미국 시장 진출에 새로운 이정표를 세웠다.\n\n이 영화는 미국 전역 1,500개 이상의 극장에서 상영되고 있으며, 한인 관객뿐 아니라 주류 관객들 사이에서도 입소문을 타고 흥행하고 있다.\n\n로튼토마토에서 관객 점수 92%를 기록하며 높은 만족도를 보여주고 있다. 미국 평론가들은 할리우드 액션 영화와는 차별화된 한국식 액션 미학을 높이 평가했다.\n\n한인 극장주들은 한국 영화 상영관을 확대하고 있으며, 한인 커뮤니티에서는 단체 관람 행사도 활발하게 진행되고 있다."],
            ['title' => '한인 농장, 유기농 배추 수확 시즌 시작', 'summary' => '한인 농장에서 유기농 배추 수확 시즌이 시작되었다. 김장철을 앞두고 한인 가정의 주문이 이어지고 있으며, 직거래 가격도 안정적이다.', 'category' => '생활', 'content' => "캘리포니아 한인 농장에서 유기농 배추 수확 시즌이 시작되었다. 김장철을 앞두고 한인 가정과 식당의 주문이 쇄도하고 있다.\n\n한인 농장주에 따르면, 올해 배추 작황이 양호하여 수확량이 전년 대비 20% 증가했다. 직거래 가격은 배추 한 포기당 3~4달러로 안정적이다.\n\n최근에는 유기농 인증을 받은 한인 농장이 늘어나면서, 건강을 중시하는 한인 소비자들의 직거래 수요가 꾸준히 증가하고 있다.\n\n한인 농업인 협회는 올해 김장 시즌에 맞춰 한인 마트와 연계한 직거래 장터를 운영할 계획이며, 공동구매 프로그램도 준비하고 있다."],
            ['title' => '미주 한인 과학자, 노벨상 후보 거론', 'summary' => '미주에서 활동 중인 한인 과학자가 올해 노벨 화학상 후보로 거론되고 있다. 나노기술 분야에서 혁신적인 연구 성과를 낸 것이 주목받고 있다.', 'category' => '기타', 'content' => "미주에서 활동 중인 한인 과학자가 올해 노벨 화학상 유력 후보로 거론되며 한인 사회의 큰 관심을 모으고 있다.\n\n이 과학자는 미국 명문 대학 교수로 재직 중이며, 나노기술을 활용한 차세대 에너지 저장 기술 개발로 세계적인 주목을 받아왔다. 그의 논문은 네이처와 사이언스에 50편 이상 게재되었다.\n\n한국에서 서울대를 졸업한 후 미국에서 박사 학위를 취득한 그는, 30년간 나노기술 분야의 최전선에서 연구해온 한인 1세대 과학자이다.\n\n한인 과학자 협회는 그의 노벨상 수상 가능성에 큰 기대를 걸고 있으며, 한인 과학자의 노벨상 수상은 전체 한인 커뮤니티에 큰 자부심이 될 것이라고 말했다."],
            ['title' => '한인 커뮤니티, 허리케인 피해 지역 구호 성금 모금', 'summary' => '한인 커뮤니티가 허리케인 피해 지역을 위한 성금 모금 활동을 시작했다. 한인 교회와 단체들이 연합하여 구호물품도 함께 전달할 계획이다.', 'category' => '기타', 'content' => "한인 커뮤니티가 최근 허리케인으로 큰 피해를 입은 남부 지역을 위한 성금 모금 활동을 시작했다.\n\n한인 교회 연합, 한인회, 한인 상공회의소 등이 연합하여 모금 캠페인을 진행하고 있으며, 현재까지 약 8만 달러의 성금이 모금되었다. 목표 금액은 20만 달러이다.\n\n또한 생수, 식료품, 의류, 위생용품 등 구호물품도 모아 피해 지역에 직접 전달할 계획이다. 한인 트럭 운전사들이 자원봉사로 운송을 맡기로 했다.\n\n한인회장은 한인 커뮤니티가 어려운 이웃을 돕는 전통을 이어가고 있다며, 인종과 종교를 넘어선 나눔의 정신이 한인 사회의 자랑이라고 말했다."],
            ['title' => '한인 프로게이머, e스포츠 세계대회 우승', 'summary' => '한인 프로게이머가 e스포츠 세계대회에서 우승을 차지했다. 미국 국적의 한인 선수로서 한인 커뮤니티의 큰 자부심이 되고 있다.', 'category' => '스포츠', 'content' => "한인 프로게이머가 e스포츠 세계대회에서 우승을 차지하며 상금 50만 달러를 획득했다. 미국 국적의 한인 선수로서 한인 커뮤니티의 큰 자부심이 되고 있다.\n\n결승전에서 유럽 챔피언을 3-1로 꺾고 우승한 그는, 경기 후 태극기와 성조기를 동시에 들어올려 관중들의 큰 박수를 받았다.\n\n한인 2세인 그는 어린 시절부터 게임에 재능을 보여 16세에 프로 데뷔했으며, 22세의 나이에 세계 최정상에 올랐다.\n\n한인 e스포츠 커뮤니티에서는 그의 우승을 축하하는 행사가 열리고 있으며, 한인 청소년들 사이에서 e스포츠에 대한 관심도 높아지고 있다."],
            ['title' => '한인 타운 주차난 해소, 새 공영주차장 건설 확정', 'summary' => 'LA시가 한인타운 지역에 새 공영주차장 건설을 확정했다. 500대 규모의 주차장이 내년 완공 예정으로, 만성적인 주차난 해소에 기여할 전망이다.', 'category' => '생활', 'content' => "LA시가 한인타운 중심부에 500대 규모의 새 공영주차장 건설을 확정했다. 착공은 올해 하반기, 완공은 내년 말로 예정되어 있다.\n\n새 주차장은 6층 구조의 입체 주차장으로, 올림픽 블러바드와 노르만디 애비뉴 인근에 건설된다. 주차 요금은 시간당 2달러로 민간 주차장보다 저렴하게 책정될 예정이다.\n\n한인타운의 만성적인 주차난은 상권 활성화의 가장 큰 장애물로 지적되어 왔다. 한인 상인들은 주차 문제로 고객이 줄어드는 것이 가장 큰 고민이었다고 전했다.\n\n한인 상인회장은 새 공영주차장이 한인타운 경제 활성화에 크게 기여할 것이라며, LA시의 결정에 감사를 표했다."],
            ['title' => '한인 수의사, 반려동물 건강 세미나 개최', 'summary' => '한인 수의사회가 반려동물 건강 관리 세미나를 개최한다. 반려견과 반려묘의 계절별 건강 관리법과 예방접종 일정에 대해 안내할 예정이다.', 'category' => '생활', 'content' => "한인 수의사회가 반려동물 건강 관리 세미나를 개최하여 한인 반려인들에게 유용한 정보를 제공한다.\n\n세미나에서는 반려견과 반려묘의 계절별 건강 관리법, 필수 예방접종 일정, 올바른 사료 선택법, 응급 상황 대처법 등이 안내된다.\n\n특히 한인 가정에서 반려동물에게 한국 음식을 먹이는 경우가 많은데, 양파, 마늘, 포도 등 반려동물에게 위험한 음식에 대한 주의사항도 강조할 예정이다.\n\n한인 수의사회 관계자는 미국에서 반려동물 의료비가 매우 높으므로, 예방 중심의 건강 관리가 반려동물과 보호자 모두에게 유익하다고 조언했다."],
            ['title' => '한인 방송인, 미국 주류 방송 앵커 발탁', 'summary' => '한인 2세 방송인이 미국 주요 방송사의 뉴스 앵커로 발탁되었다. 한인계 미국인으로서는 이례적인 발탁으로 한인 사회의 큰 축하를 받고 있다.', 'category' => '기타', 'content' => "한인 2세 방송인이 미국 주요 방송사의 저녁 뉴스 앵커로 발탁되어 한인 사회에 큰 화제가 되고 있다.\n\n한인계 미국인이 주요 네트워크 방송의 메인 뉴스 앵커를 맡는 것은 이번이 처음으로, 한인 미디어계의 역사적인 순간으로 기록되고 있다.\n\n새 앵커는 한인 이민자 가정에서 성장하여 컬럼비아 대학 저널리즘 스쿨을 졸업한 후, 지역 방송에서 15년간 경력을 쌓아왔다. 탁월한 취재력과 차분한 진행 스타일로 정평이 나 있다.\n\n한인 언론인 협회는 축하 성명을 통해 한인 차세대가 미국 주류 사회에서 더 많이 활약할 수 있는 길을 열었다고 평가했다."],
        ];
    }
}
